export enum TopicId {
  SAUDE = 'saude',
  EDUCACAO = 'educacao',
  DESENVOLVIMENTO_SOCIAL = 'social',
  FINANCAS = 'financas',
  ESPORTE_CULTURA_LAZER = 'esporte',
  AGRICULTURA = 'agricultura',
  INFRAESTRUTURA = 'infraestrutura',
  PLANEJAMENTO = 'planejamento',
}

export interface ProgressUpdate {
  date: number;
  percentage: number;
  whatWasDone: string;
  whatIsMissing: string;
}

export interface SemaforoConfig {
  green: string;
  yellow: string;
  red: string;
}

export interface ReportSection {
  // 1. Identificação
  secretaria: string;
  periodo: string;
  responsavelPolitico: string;
  pontoFocal: string; // Nome | Cargo | Telefone | E-mail

  // 2. Resumo Executivo
  resumoAvanços: string;
  resumoAtrasos: string;
  resumoDecisoes: string;

  // 3. Indicadores-Chave (Tabela)
  indicadoresChave: Array<{
    nome: string;
    meta: string;
    resultado: string;
    status: 'green' | 'yellow' | 'red';
    tendencia: 'up' | 'stable' | 'down';
    fonte: string;
  }>;

  // 4. Metas Prioritárias
  metasPrioritarias: Array<{
    meta: string;
    prazo: string;
    responsavel: string;
    status: 'green' | 'yellow' | 'red';
    evidencia: string;
    obs: string;
  }>;

  // 5. Problemas Críticos
  problemasCriticos: Array<{
    problema: string;
    impacto: 'Alto' | 'Médio' | 'Baixo';
    causa: string;
    acao: string;
    prazo: string;
  }>;

  // 6. Decisões Prefeito
  decisoesPrefeito: Array<{
    tema: string;
    decisao: string;
    consequencia: string;
    prazo: string;
  }>;

  // 7. Riscos e Alertas
  riscos: {
    tipos: string[]; // Fiscal, Jurídico, etc.
    descricao: string;
  };

  // 8. Compromissos Próximo Período
  compromissos: Array<{
    compromisso: string;
    prazo: string;
    responsavel: string;
    evidencia: string;
  }>;

  // 9. Anexos
  anexos: string;
}

export interface ChartConfig {
  type: 'bar' | 'line' | 'pie';
  title: string;
  data?: any;
  color?: string;
  options?: any;
}

export interface Post {
  id: string;
  topicId: TopicId;
  description: string;
  chartConfig: ChartConfig;
  createdAt: number;

  // Novos campos de Gestão
  responsavel: string;
  fonteOficial: string;
  recorrencia: string;
  dataAtualizacao: number;
  semaforoRules: SemaforoConfig;
  progress: number; // 0-100
  progressHistory: ProgressUpdate[];
  report: ReportSection;
}

export interface TopicDef {
  id: TopicId;
  label: string;
  iconName: string;
  color: string;
  description: string;
}

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, useParams, Link, useNavigate } from 'react-router-dom';
import { ArrowLeft, LayoutDashboard, Lock, MessageCircle, AlertCircle, Maximize2, X, Calendar, User, Database, Info, History, CheckCircle2, TrendingUp, TrendingDown, Minus, Clock, FileText, AlertTriangle } from 'lucide-react';
import { TOPICS } from './constants';
import { Post, TopicId, ChartConfig, ProgressUpdate } from './types';
import { TopicCard } from './components/TopicCard';
import { ChartRenderer } from './components/ChartRenderer';
import { AdminPanel } from './components/AdminPanel';

function App() {
  const [posts, setPosts] = useState<Post[]>([]);
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [usingServer, setUsingServer] = useState(true);

  const fetchPosts = async () => {
    try {
      setIsLoading(true);
      const response = await fetch('/api/posts');
      if (!response.ok) throw new Error('Erro servidor');
      const json = await response.json();
      setPosts(json.data || []);
      setUsingServer(true);
    } catch (err) {
      setUsingServer(false);
      const localData = localStorage.getItem('posts');
      if (localData) setPosts(JSON.parse(localData));
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { fetchPosts(); }, []);

  const handleAddPost = async (topicId: TopicId, description: string, chartConfig: ChartConfig, extraData: any) => {
    const newPost: Post = {
      id: Date.now().toString(),
      topicId,
      description,
      chartConfig,
      createdAt: Date.now(),
      ...extraData
    };

    if (usingServer) {
      try {
        const response = await fetch('/api/posts', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(newPost),
        });
        if (!response.ok) throw new Error('Erro salvar');
        setPosts(prev => [newPost, ...prev]);
        return true;
      } catch (err) { return false; }
    } else {
      const updated = [newPost, ...posts];
      setPosts(updated);
      localStorage.setItem('posts', JSON.stringify(updated));
      return true;
    }
  };

  const handleEditPost = async (postId: string, topicId: TopicId, description: string, chartConfig: ChartConfig, extraData: any) => {
    const updatedFields = { topicId, description, chartConfig, ...extraData };
    if (usingServer) {
      try {
        const response = await fetch(`/api/posts/${postId}`, {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(updatedFields),
        });
        if (!response.ok) throw new Error('Erro update');
        setPosts(prev => prev.map(p => p.id === postId ? { ...p, ...updatedFields } : p));
        return true;
      } catch (err) { return false; }
    } else {
      const updated = posts.map(p => p.id === postId ? { ...p, ...updatedFields } : p);
      setPosts(updated);
      localStorage.setItem('posts', JSON.stringify(updated));
      return true;
    }
  };

  const handleDeletePost = async (postId: string) => {
    if (usingServer) {
      await fetch(`/api/posts/${postId}`, { method: 'DELETE' });
      setPosts(prev => prev.filter(p => p.id !== postId));
    } else {
      const updated = posts.filter(p => p.id !== postId);
      setPosts(updated);
      localStorage.setItem('posts', JSON.stringify(updated));
    }
  };

  return (
    <Router>
      <div className="min-h-screen bg-[#020617] text-slate-100 font-sans">
        <header className="bg-slate-900/90 backdrop-blur-md sticky top-0 z-40 border-b border-slate-800">
          <div className="max-w-7xl mx-auto px-4 h-20 flex items-center justify-between">
            <Link to="/" className="flex items-center gap-4">
              <img src="https://pmsgc-goncalinho.wvai75.easypanel.host/brasao.png" className="h-10 w-auto" alt="Logo" />
              <div>
                <h1 className="text-xl font-bold text-white leading-none">Gestão de Indicadores</h1>
                <span className="text-[10px] text-emerald-400 font-bold uppercase tracking-widest">Sala de Situação</span>
              </div>
            </Link>
            <button onClick={() => setIsAdminOpen(true)} className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-slate-400 hover:text-emerald-400 border border-slate-700 rounded-lg">
              <Lock size={14} /> Gestão
            </button>
          </div>
        </header>

        <main className="max-w-7xl mx-auto px-4 py-8">
          <Routes>
            <Route path="/" element={<DashboardView isLoading={isLoading} />} />
            <Route path="/topic/:topicId" element={<TopicDetailView posts={posts} isLoading={isLoading} />} />
          </Routes>
        </main>

        {isAdminOpen && (
          <AdminPanel 
            isOpen={isAdminOpen}
            onClose={() => setIsAdminOpen(false)}
            posts={posts}
            onAddPost={handleAddPost}
            onEditPost={handleEditPost}
            onDeletePost={handleDeletePost}
            usingServer={usingServer}
          />
        )}
      </div>
    </Router>
  );
}

const DashboardView = ({ isLoading }: { isLoading: boolean }) => {
  const navigate = useNavigate();
  return (
    <div className="space-y-10 py-10">
      <div className="text-center">
        <h2 className="text-4xl font-black text-white mb-2">Monitoramento Municipal</h2>
        <p className="text-slate-400 max-w-xl mx-auto">Acompanhamento em tempo real de metas, indicadores e entregas prioritárias.</p>
      </div>
      {isLoading ? <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-10 w-10 border-b-2 border-emerald-500"></div></div> : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {TOPICS.map(topic => <TopicCard key={topic.id} topic={topic} onClick={(id) => navigate(`/topic/${id}`)} />)}
        </div>
      )}
    </div>
  );
};

const TopicDetailView = ({ posts, isLoading }: { posts: Post[], isLoading: boolean }) => {
  const { topicId } = useParams();
  const [selectedPost, setSelectedPost] = useState<Post | null>(null);
  const topic = TOPICS.find(t => t.id === topicId);
  const topicPosts = posts.filter(p => p.topicId === topicId).sort((a, b) => b.createdAt - a.createdAt);

  if (!topic) return <div className="text-center py-20">Não encontrado</div>;

  return (
    <div>
      <div className="mb-10 flex items-end justify-between border-b border-slate-800 pb-6">
        <div>
          <Link to="/" className="text-xs text-slate-500 hover:text-white flex items-center gap-1 mb-2"><ArrowLeft size={12}/> Voltar</Link>
          <h2 className="text-3xl font-bold">{topic.label}</h2>
          <p className="text-slate-400 mt-1">{topic.description}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {topicPosts.map(post => (
          <div key={post.id} className="bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden hover:border-slate-700 transition-all flex flex-col h-full group">
            <div className="p-5 flex justify-between items-start border-b border-slate-800 bg-slate-900/80">
              <h3 className="font-bold text-slate-200">{post.chartConfig.title}</h3>
              <button onClick={() => setSelectedPost(post)} className="p-2 text-slate-500 hover:text-emerald-400 transition-colors"><Maximize2 size={18}/></button>
            </div>
            <div className="p-6 flex-1 space-y-4">
              <div className="h-56 bg-slate-950 rounded-xl p-4 border border-slate-800">
                <ChartRenderer config={post.chartConfig} />
              </div>
              <div className="space-y-2">
                <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase">
                  <span>Progresso da Entrega</span>
                  <span className="text-emerald-400">{post.progress || 0}%</span>
                </div>
                <div className="h-2 bg-slate-800 rounded-full overflow-hidden">
                  <div className="h-full bg-emerald-500 transition-all duration-1000" style={{ width: `${post.progress || 0}%` }}></div>
                </div>
              </div>
              <p className="text-sm text-slate-400 line-clamp-2">{post.description}</p>
              <div className="flex items-center gap-4 text-[10px] text-slate-500 font-medium">
                <span className="flex items-center gap-1"><User size={12}/> {post.responsavel}</span>
                <span className="flex items-center gap-1"><Clock size={12}/> {new Date(post.dataAtualizacao).toLocaleDateString()}</span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {selectedPost && (
        <ReportModal post={selectedPost} onClose={() => setSelectedPost(null)} />
      )}
    </div>
  );
};

const ReportModal = ({ post, onClose }: { post: Post, onClose: () => void }) => {
  const r = post.report || {} as any;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 p-4 backdrop-blur-md overflow-y-auto" onClick={onClose}>
      <div className="bg-[#0f172a] w-full max-w-6xl rounded-3xl border border-slate-800 shadow-2xl flex flex-col max-h-[95vh] animate-in zoom-in duration-300 overflow-hidden" onClick={e => e.stopPropagation()}>

        {/* Header Relatório */}
        <div className="p-6 border-b border-slate-800 bg-slate-900/50 flex justify-between items-center shrink-0">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <span className="bg-emerald-500 text-white text-[9px] font-black px-2 py-0.5 rounded uppercase">Relatório Executivo</span>
              <span className="text-slate-500 text-[10px] font-bold uppercase">{post.recorrencia}</span>
            </div>
            <h2 className="text-2xl font-black text-white tracking-tight">{post.chartConfig.title}</h2>
          </div>
          <button onClick={onClose} className="p-3 bg-slate-800 hover:bg-red-500/20 text-slate-400 hover:text-red-400 rounded-full transition-all"><X size={24}/></button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 md:p-10 space-y-12 custom-scrollbar">

          {/* 1. Identificação & Barra de Progresso */}
          <div className="grid lg:grid-cols-3 gap-8 items-start">
            <div className="lg:col-span-2 space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <div className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800">
                  <span className="text-[10px] font-bold text-slate-500 uppercase block mb-1">Secretaria/Órgão</span>
                  <p className="text-sm font-semibold">{r.secretaria || 'Não informada'}</p>
                </div>
                <div className="bg-slate-900/50 p-4 rounded-2xl border border-slate-800">
                  <span className="text-[10px] font-bold text-slate-500 uppercase block mb-1">Período Referência</span>
                  <p className="text-sm font-semibold">{r.periodo || 'N/A'}</p>
                </div>
              </div>
              <div className="bg-slate-900/80 p-6 rounded-2xl border border-slate-700 shadow-inner space-y-4">
                <div className="flex justify-between items-end">
                   <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest">Evolução da Entrega</h4>
                   <span className="text-3xl font-black text-emerald-400">{post.progress}%</span>
                </div>
                <div className="h-4 bg-slate-950 rounded-full border border-slate-800 overflow-hidden">
                  <div className="h-full bg-gradient-to-r from-emerald-600 to-cyan-500" style={{ width: `${post.progress}%` }}></div>
                </div>
                {post.progress < 100 && post.progressHistory?.length > 0 && (
                  <div className="bg-slate-950/50 p-3 rounded-xl border border-slate-800 flex gap-4 items-center">
                    <Info size={16} className="text-amber-400 shrink-0" />
                    <div className="text-xs leading-relaxed">
                       <span className="font-bold text-slate-300">O que falta:</span> {post.progressHistory[0].whatIsMissing}
                    </div>
                  </div>
                )}
