                  <p className="text-[11px] text-slate-400 leading-tight"><span className="text-emerald-400 font-bold block mb-1">DENTRO DA META</span> {post.semaforoRules?.green}</p>
                </div>
                <div className="flex gap-4 items-center border-l-2 border-amber-500 pl-4">
                  <div className="w-10 h-10 rounded-full bg-amber-500/10 flex items-center justify-center shrink-0">🟡</div>
                  <p className="text-[11px] text-slate-400 leading-tight"><span className="text-amber-400 font-bold block mb-1">ALERTA/ATENÇÃO</span> {post.semaforoRules?.yellow}</p>
                </div>
                <div className="flex gap-4 items-center border-l-2 border-red-500 pl-4">
                  <div className="w-10 h-10 rounded-full bg-red-500/10 flex items-center justify-center shrink-0">🔴</div>
                  <p className="text-[11px] text-slate-400 leading-tight"><span className="text-red-400 font-bold block mb-1">CRÍTICO/EM ATRASO</span> {post.semaforoRules?.red}</p>
                </div>
             </div>
          </section>

          {/* 5. Histórico de Movimentação */}
          <section className="space-y-6">
            <h3 className="text-lg font-black flex items-center gap-2 text-white"><History className="text-emerald-500" size={20}/> Histórico de Movimentações</h3>
            <div className="space-y-4">
               {post.progressHistory?.map((up: ProgressUpdate, i: number) => (
                 <div key={i} className="relative pl-8 border-l border-slate-800 pb-8 last:pb-0">
                    <div className="absolute -left-1.5 top-0 w-3 h-3 rounded-full bg-emerald-500 border-2 border-slate-900"></div>
                    <div className="bg-slate-900/40 p-5 rounded-2xl border border-slate-800 group hover:border-slate-700 transition-colors">
                      <div className="flex justify-between items-center mb-3">
                        <span className="text-[10px] font-black text-slate-500 uppercase">{new Date(up.date).toLocaleDateString()}</span>
                        <span className="bg-emerald-500/10 text-emerald-400 text-[10px] font-bold px-2 py-0.5 rounded border border-emerald-500/20">{up.percentage}%</span>
                      </div>
                      <div className="space-y-3">
                        <div>
                           <span className="text-[9px] font-bold text-emerald-400 uppercase block mb-1">O que foi realizado:</span>
                           <p className="text-xs text-slate-300 leading-relaxed">{up.whatWasDone}</p>
                        </div>
                        {up.percentage < 100 && (
                          <div className="pt-2 border-t border-slate-800/50">
                            <span className="text-[9px] font-bold text-amber-400 uppercase block mb-1">O que falta para concluir:</span>
                            <p className="text-xs text-slate-400 leading-relaxed italic">{up.whatIsMissing}</p>
                          </div>
                        )}
                      </div>
                    </div>
                 </div>
               ))}
            </div>
          </section>

          {/* Seção de Riscos */}
          {r.riscos?.descricao && (
            <section className="bg-red-950/10 border border-red-900/30 p-8 rounded-3xl space-y-4">
              <div className="flex items-center gap-3">
                <AlertTriangle className="text-red-500" />
                <h3 className="text-lg font-black text-white">7. Riscos e Alertas Críticos</h3>
              </div>
              <div className="flex flex-wrap gap-2">
                {r.riscos.tipos?.map((t: string) => (
                  <span key={t} className="px-2 py-0.5 bg-red-900/40 text-red-300 text-[9px] font-bold rounded-full uppercase border border-red-800/50">{t}</span>
                ))}
              </div>
              <p className="text-sm text-slate-300 italic border-l-2 border-red-500 pl-4 py-1">"{r.riscos.descricao}"</p>
            </section>
          )}

        </div>

        <div className="p-6 border-t border-slate-800 bg-slate-900/50 flex justify-between items-center text-[10px] font-bold text-slate-500 uppercase">
           <span>Fonte: {post.fonteOficial}</span>
           <span>Atualizado em: {new Date(post.dataAtualizacao).toLocaleString()}</span>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { X, Trash2, Plus, Lock, Palette, Database, Type, Wifi, WifiOff, Pencil, RefreshCw, BarChart3, LineChart, PieChart, Code, Eye, Table as TableIcon, ClipboardList, TrendingUp, History, ShieldAlert } from 'lucide-react';
import { ChartConfig, Post, TopicId, SemaforoConfig, ProgressUpdate, ReportSection } from '../types';
import { TOPICS } from '../constants';
import { ChartRenderer } from './ChartRenderer';

interface AdminPanelProps {
  isOpen: boolean;
  onClose: () => void;
  posts: Post[];
  onAddPost: (topicId: TopicId, description: string, chartConfig: ChartConfig, extra: any) => Promise<boolean | void>;
  onEditPost: (postId: string, topicId: TopicId, description: string, chartConfig: ChartConfig, extra: any) => Promise<boolean | void>;
  onDeletePost: (postId: string) => void;
  usingServer: boolean;
}

const INITIAL_REPORT: ReportSection = {
  secretaria: '', periodo: '', responsavelPolitico: '', pontoFocal: '',
  resumoAvanços: '', resumoAtrasos: '', resumoDecisoes: '',
  indicadoresChave: [], metasPrioritarias: [], problemasCriticos: [], decisoesPrefeito: [],
  riscos: { tipos: [], descricao: '' }, compromissos: [], anexos: ''
};

const INITIAL_SEMAFORO: SemaforoConfig = {
  green: 'Meta atingida conforme planejado.',
  yellow: 'Atraso leve ou atenção necessária para correção de rumo.',
  red: 'Ação crítica necessária. Impacto direto na entrega final.'
};

export const AdminPanel: React.FC<AdminPanelProps> = ({ 
  isOpen, onClose, posts, onAddPost, onEditPost, onDeletePost, usingServer
}) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [authError, setAuthError] = useState(false);
  const [activeTab, setActiveTab] = useState<'add' | 'list'>('add');
  const [adminSection, setAdminSection] = useState<'basic' | 'report' | 'progress'>('basic');
  const [editingPostId, setEditingPostId] = useState<string | null>(null);

  // Form States
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [selectedTopic, setSelectedTopic] = useState<TopicId>(TopicId.SAUDE);
  const [selectedColor, setSelectedColor] = useState('#10b981');
  const [responsavel, setResponsavel] = useState('');
  const [fonteOficial, setFonteOficial] = useState('');
  const [recorrencia, setRecorrencia] = useState('Mensal');
  const [semaforoRules, setSemaforoRules] = useState<SemaforoConfig>(INITIAL_SEMAFORO);
  const [report, setReport] = useState<ReportSection>(INITIAL_REPORT);
  const [progress, setProgress] = useState(0);
  const [progressHistory, setProgressHistory] = useState<ProgressUpdate[]>([]);

  // Visual Builder States
  const [builderType, setBuilderType] = useState<'bar' | 'line' | 'pie'>('bar');
  const [builderSeries, setBuilderSeries] = useState<string[]>(['Valor']); 
  const [builderRows, setBuilderRows] = useState<any[]>([{ label: 'Jan', 'Valor': 10 }]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === 'azul') { setIsAuthenticated(true); setAuthError(false); }
    else { setAuthError(true); }
  };

  const resetForm = () => {
    setEditingPostId(null); setTitle(''); setDescription(''); setProgress(0); setProgressHistory([]);
    setReport(INITIAL_REPORT); setSemaforoRules(INITIAL_SEMAFORO); setAdminSection('basic');
  };

  const handleEditClick = (post: Post) => {
    setEditingPostId(post.id); setSelectedTopic(post.topicId); setTitle(post.chartConfig.title);
    setDescription(post.description); setResponsavel(post.responsavel || '');
    setFonteOficial(post.fonteOficial || ''); setRecorrencia(post.recorrencia || 'Mensal');
    setSemaforoRules(post.semaforoRules || INITIAL_SEMAFORO); setReport(post.report || INITIAL_REPORT);
    setProgress(post.progress || 0); setProgressHistory(post.progressHistory || []);
    setBuilderType(post.chartConfig.type as any);
    if (Array.isArray(post.chartConfig.data)) setBuilderRows(post.chartConfig.data);
    setActiveTab('add');
  };

  const handleSubmit = async () => {
    const config: ChartConfig = {
      type: builderType, title, color: selectedColor,
      data: builderRows.map(r => ({ ...r }))
    };
    const extra = {
      responsavel, fonteOficial, recorrencia, dataAtualizacao: Date.now(),
      semaforoRules, progress, progressHistory, report
    };
    let success;
    if (editingPostId) success = await onEditPost(editingPostId, selectedTopic, description, config, extra);
    else success = await onAddPost(selectedTopic, description, config, extra);
    if (success !== false) { resetForm(); setActiveTab('list'); }
  };

  const addProgressUpdate = () => {
    const p = prompt("Nova porcentagem total (0-100):");
    if (p === null) return;
    const done = prompt("O que foi realizado nesta etapa?");
    const missing = prompt("O que falta para concluir?");
    const newUpdate = { date: Date.now(), percentage: Number(p), whatWasDone: done || '', whatIsMissing: missing || '' };
    setProgress(Number(p));
    setProgressHistory([newUpdate, ...progressHistory]);
  };

  if (!isAuthenticated) {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-xl">
        <div className="bg-slate-900 border border-slate-700 rounded-3xl shadow-2xl w-full max-w-md p-10 text-center space-y-8">
          <div className="mx-auto w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center border border-emerald-500/20"><Lock className="text-emerald-400" size={32}/></div>
          <h2 className="text-2xl font-black text-white">Sala de Situação</h2>
          <form onSubmit={handleLogin} className="space-y-4">
            <input type="password" value={passwordInput} onChange={(e) => setPasswordInput(e.target.value)} placeholder="Senha de Gestor" className="w-full p-4 bg-slate-950 border border-slate-800 text-white rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none text-center font-bold tracking-widest" autoFocus />
            {authError && <p className="text-red-400 text-xs font-bold uppercase">Senha incorreta</p>}
            <button type="submit" className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black shadow-lg shadow-emerald-900/40 hover:bg-emerald-500 transition-all">Acessar</button>
            <button type="button" onClick={onClose} className="text-xs text-slate-500 hover:text-white uppercase font-bold">Cancelar</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-4">
      <div className="bg-[#0f172a] border border-slate-800 rounded-3xl w-full max-w-6xl shadow-2xl overflow-hidden flex flex-col h-[95vh]">
        <div className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-900/50">
          <div className="flex items-center gap-6">
            <h2 className="text-xl font-black text-white uppercase tracking-tighter">Painel de Gestão Técnica</h2>
            <div className="flex bg-slate-800/50 p-1 rounded-xl">
              <button onClick={() => setActiveTab('add')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${activeTab === 'add' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white'}`}>{editingPostId ? 'Editar' : 'Novo Indicador'}</button>
              <button onClick={() => setActiveTab('list')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${activeTab === 'list' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white'}`}>Listagem</button>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-500 transition-colors"><X size={24}/></button>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar">
          {activeTab === 'add' ? (
            <div className="p-8 space-y-10 pb-24">

              {/* Menu Secundário Administrativo */}
              <div className="flex gap-2 border-b border-slate-800 pb-2">
                <button onClick={() => setAdminSection('basic')} className={`px-4 py-2 text-xs font-bold flex items-center gap-2 ${adminSection === 'basic' ? 'text-emerald-400 border-b-2 border-emerald-400' : 'text-slate-500 hover:text-slate-300'}`}><Type size={14}/> 1. Básico & Gráfico</button>
                <button onClick={() => setAdminSection('report')} className={`px-4 py-2 text-xs font-bold flex items-center gap-2 ${adminSection === 'report' ? 'text-emerald-400 border-b-2 border-emerald-400' : 'text-slate-500 hover:text-slate-300'}`}><ClipboardList size={14}/> 2. Relatório (9 Tópicos)</button>
                <button onClick={() => setAdminSection('progress')} className={`px-4 py-2 text-xs font-bold flex items-center gap-2 ${adminSection === 'progress' ? 'text-emerald-400 border-b-2 border-emerald-400' : 'text-slate-500 hover:text-slate-300'}`}><TrendingUp size={14}/> 3. Evolução/Barra</button>
              </div>

              {adminSection === 'basic' && (
                <div className="space-y-6">
                  <div className="grid md:grid-cols-3 gap-6">
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-500 uppercase">Título do Indicador</label>
                      <input value={title} onChange={e => setTitle(e.target.value)} className="w-full p-3 bg-slate-900 border border-slate-800 rounded-xl text-white outline-none focus:border-emerald-500" placeholder="Ex: Meta de Vacinação" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-500 uppercase">Secretaria</label>
                      <input value={report.secretaria} onChange={e => setReport({...report, secretaria: e.target.value})} className="w-full p-3 bg-slate-900 border border-slate-800 rounded-xl text-white outline-none focus:border-emerald-500" placeholder="Ex: SMS" />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-500 uppercase">Fonte de Dados</label>
                      <input value={fonteOficial} onChange={e => setFonteOficial(e.target.value)} className="w-full p-3 bg-slate-900 border border-slate-800 rounded-xl text-white outline-none focus:border-emerald-500" placeholder="Ex: DATASUS" />
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-500 uppercase">Gráfico Visual (Eixo X | Valor)</label>
                    <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden">
                      <table className="w-full text-xs text-left">
                        <thead className="bg-slate-950 text-slate-500">
                          <tr><th className="p-3">Rótulo</th><th className="p-3">Valor</th><th className="p-3 w-10"></th></tr>
                        </thead>
                        <tbody>
                          {builderRows.map((r, i) => (
                            <tr key={i} className="border-t border-slate-800">
                              <td className="p-1"><input value={r.label} onChange={e => { const n = [...builderRows]; n[i].label = e.target.value; setBuilderRows(n); }} className="w-full bg-transparent p-2 text-white outline-none" /></td>
                              <td className="p-1"><input type="number" value={r.Valor} onChange={e => { const n = [...builderRows]; n[i].Valor = e.target.value; setBuilderRows(n); }} className="w-full bg-transparent p-2 text-emerald-400 outline-none" /></td>
                              <td className="p-1"><button onClick={() => setBuilderRows(builderRows.filter((_, idx) => idx !== i))} className="text-slate-600 hover:text-red-500"><Trash2 size={14}/></button></td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                      <button onClick={() => setBuilderRows([...builderRows, {label: '', Valor: 0}])} className="w-full py-2 bg-slate-800/50 text-[10px] font-bold text-slate-500 hover:text-white">+ Adicionar Linha</button>
                    </div>
                  </div>
                </div>
              )}

              {adminSection === 'report' && (
                <div className="space-y-8">
                  <div className="grid md:grid-cols-2 gap-6">
                    <div className="space-y-4 bg-slate-900/30 p-6 rounded-3xl border border-slate-800">
                      <h4 className="text-xs font-black text-emerald-400 uppercase tracking-widest">Identificação Política</h4>
                      <input value={report.responsavelPolitico} onChange={e => setReport({...report, responsavelPolitico: e.target.value})} className="w-full p-3 bg-slate-950 border border-slate-800 rounded-xl text-xs text-white" placeholder="Secretário Responsável" />
                      <input value={report.periodo} onChange={e => setReport({...report, periodo: e.target.value})} className="w-full p-3 bg-slate-950 border border-slate-800 rounded-xl text-xs text-white" placeholder="Período de Referência" />
                    </div>
                    <div className="space-y-4 bg-slate-900/30 p-6 rounded-3xl border border-slate-800">
                      <h4 className="text-xs font-black text-amber-400 uppercase tracking-widest">Regras do Semáforo</h4>
                      <input value={semaforoRules.green} onChange={e => setSemaforoRules({...semaforoRules, green: e.target.value})} className="w-full p-2 bg-slate-950 border border-slate-800 rounded-xl text-[10px] text-emerald-400" placeholder="Significado Verde" />
                      <input value={semaforoRules.yellow} onChange={e => setSemaforoRules({...semaforoRules, yellow: e.target.value})} className="w-full p-2 bg-slate-950 border border-slate-800 rounded-xl text-[10px] text-amber-400" placeholder="Significado Amarelo" />
                      <input value={semaforoRules.red} onChange={e => setSemaforoRules({...semaforoRules, red: e.target.value})} className="w-full p-2 bg-slate-950 border border-slate-800 rounded-xl text-[10px] text-red-400" placeholder="Significado Vermelho" />
                    </div>
                  </div>

                  <div className="space-y-4">
                    <h4 className="text-xs font-black text-slate-500 uppercase flex items-center gap-2"><ShieldAlert size={14}/> Gestão de Riscos</h4>
                    <textarea value={report.riscos.descricao} onChange={e => setReport({...report, riscos: {...report.riscos, descricao: e.target.value}})} className="w-full p-4 bg-slate-900 border border-slate-800 rounded-2xl text-xs text-slate-300 min-h-[100px]" placeholder="Descreva os riscos fiscais, jurídicos ou políticos..." />
                  </div>
                </div>
              )}

              {adminSection === 'progress' && (
                <div className="space-y-8 max-w-2xl mx-auto">
                   <div className="text-center space-y-2">
                     <h3 className="text-xl font-black text-white">Gestão da Barra de Carregamento</h3>
