                   </div>
                   <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 space-y-6">
                      <div className="flex justify-between items-end">
                        <span className="text-xs font-bold text-slate-400">Progresso Atual</span>
                        <span className="text-2xl font-black text-emerald-400">{progress}%</span>
                      </div>
                      <div className="h-4 bg-slate-950 rounded-full border border-slate-800 overflow-hidden">
                        <div className="h-full bg-emerald-500" style={{ width: `${progress}%` }}></div>
                      </div>
                      <button onClick={addProgressUpdate} className="w-full py-3 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-2xl shadow-lg flex items-center justify-center gap-2"><Plus size={18}/> Registrar Movimentação</button>
                   </div>
                   <div className="space-y-4">
                      <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><History size={14}/> Linha do Tempo de Edições</h4>
                      {progressHistory.map((up, i) => (
                        <div key={i} className="p-4 bg-slate-900/50 border border-slate-800 rounded-2xl flex justify-between items-center group">
                          <div>
                            <span className="text-[10px] font-bold text-slate-500">{new Date(up.date).toLocaleDateString()}</span>
                            <p className="text-xs text-slate-300 font-bold">{up.whatWasDone}</p>
                          </div>
                          <button onClick={() => setProgressHistory(progressHistory.filter((_, idx) => idx !== i))} className="p-2 text-slate-600 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={16}/></button>
                        </div>
                      ))}
                   </div>
                </div>
              )}

              <div className="fixed bottom-0 left-0 right-0 p-6 bg-slate-900/80 backdrop-blur-md border-t border-slate-800 flex justify-end gap-3 z-50">
                <button onClick={resetForm} className="px-6 py-3 text-xs font-black text-slate-500 uppercase hover:text-white transition-colors">Limpar Tudo</button>
                <button onClick={handleSubmit} className="px-10 py-3 bg-emerald-600 text-white rounded-2xl font-black shadow-lg shadow-emerald-900/40 hover:-translate-y-1 transition-all">{editingPostId ? 'Salvar Alterações' : 'Publicar Relatório'}</button>
              </div>

            </div>
          ) : (
            <div className="p-8">
               <div className="bg-slate-900/30 rounded-3xl border border-slate-800 overflow-hidden">
                <table className="w-full text-left">
                  <thead>
                    <tr className="bg-slate-900 text-[10px] text-slate-500 uppercase font-black tracking-widest border-b border-slate-800">
                      <th className="p-4">Área</th>
                      <th className="p-4">Indicador</th>
                      <th className="p-4">Progresso</th>
                      <th className="p-4 text-right">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-800/50">
                    {posts.map(post => (
                      <tr key={post.id} className="hover:bg-slate-800/20 transition-colors">
                        <td className="p-4"><span className="text-[10px] font-bold bg-slate-800 px-2 py-0.5 rounded text-slate-400 uppercase">{post.topicId}</span></td>
                        <td className="p-4 font-bold text-slate-200">{post.chartConfig.title}</td>
                        <td className="p-4">
                           <div className="flex items-center gap-2">
                             <div className="w-16 h-1.5 bg-slate-800 rounded-full overflow-hidden"><div className="h-full bg-emerald-500" style={{ width: `${post.progress}%` }}></div></div>
                             <span className="text-[10px] font-bold text-emerald-400">{post.progress}%</span>
                           </div>
                        </td>
                        <td className="p-4 text-right space-x-2">
                          <button onClick={() => handleEditClick(post)} className="p-2 text-blue-400 hover:bg-blue-500/10 rounded-lg"><Pencil size={16}/></button>
                          <button onClick={() => onDeletePost(post.id)} className="p-2 text-red-400 hover:bg-red-500/10 rounded-lg"><Trash2 size={16}/></button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

