                        <p className="text-xs text-slate-400 font-bold">{post.fonteOficial || 'N/A'}</p>
                     </div>
                  </div>
               </div>
            </div>

            <div className="space-y-6">
               <div className="bg-slate-900/40 p-8 rounded-[2rem] border border-slate-800 space-y-4">
                  <h3 className="text-xl font-black text-white flex items-center gap-2"><User className="text-blue-500"/> Responsáveis</h3>
                  <div className="grid grid-cols-2 gap-4">
                     <div className="p-4 bg-slate-950 rounded-2xl border border-slate-800/50">
                        <span className="text-[10px] font-black text-slate-500 uppercase block mb-1">Político</span>
                        <p className="text-sm font-bold text-white">{post.responsavel || 'N/A'}</p>
                     </div>
                     <div className="p-4 bg-slate-950 rounded-2xl border border-slate-800/50">
                        <span className="text-[10px] font-black text-slate-500 uppercase block mb-1">Técnico</span>
                        <p className="text-sm font-bold text-white">{r.responsavelTecnico || r.pontoFocal?.nome || 'N/A'}</p>
                     </div>
                  </div>
               </div>

               <div className="bg-slate-900/40 p-8 rounded-[2rem] border border-slate-800 space-y-4">
                  <h3 className="text-xl font-black text-white flex items-center gap-2"><AlertCircle className="text-purple-500"/> Calibragem do Semáforo</h3>
                  <div className="space-y-3">
                     <div className="flex items-center gap-3 text-xs text-slate-300">
                        <div className="w-3 h-3 rounded-full bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]"></div>
                        <span>{semaforoRules.green}</span>
                     </div>
                     <div className="flex items-center gap-3 text-xs text-slate-300">
                        <div className="w-3 h-3 rounded-full bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,0.5)]"></div>
                        <span>{semaforoRules.yellow}</span>
                     </div>
                     <div className="flex items-center gap-3 text-xs text-slate-300">
                        <div className="w-3 h-3 rounded-full bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.5)]"></div>
                        <span>{semaforoRules.red}</span>
                     </div>
                  </div>
               </div>
            </div>
          </div>

          <section className="space-y-6">
            <h3 className="text-xl font-black flex items-center gap-3 text-white border-b border-slate-800 pb-4"><FileText className="text-emerald-500" size={24}/> Resumo Executivo do Período</h3>
            <div className="grid md:grid-cols-3 gap-8">
               <div className="bg-emerald-500/5 border-l-4 border-emerald-500 p-6 rounded-r-3xl">
                 <h5 className="text-[11px] font-black text-emerald-400 uppercase mb-3 flex items-center gap-2"><CheckCircle2 size={14}/> Principais Avanços</h5>
                 <p className="text-sm text-slate-300 leading-relaxed italic">"{r.resumoAvanços || 'Sem avanços relatados no período.'}"</p>
               </div>
               <div className="bg-amber-500/5 border-l-4 border-amber-500 p-6 rounded-r-3xl">
                 <h5 className="text-[11px] font-black text-amber-400 uppercase mb-3 flex items-center gap-2"><Clock size={14}/> Principais Atrasos</h5>
                 <p className="text-sm text-slate-300 leading-relaxed italic">"{r.resumoAtrasos || 'Sem gargalos relatados no período.'}"</p>
               </div>
               <div className="bg-blue-500/5 border-l-4 border-blue-500 p-6 rounded-r-3xl">
                 <h5 className="text-[11px] font-black text-blue-400 uppercase mb-3 flex items-center gap-2"><ListChecks size={14}/> Decisões do Prefeito</h5>
                 <p className="text-sm text-slate-300 leading-relaxed italic">"{r.resumoDecisoes || 'Sem demandas de decisão no período.'}"</p>
               </div>
            </div>
          </section>

          <section className="space-y-6">
            <h3 className="text-xl font-black flex items-center gap-3 text-white border-b border-slate-800 pb-4"><History className="text-purple-500" size={24}/> Detalhamento do Progresso</h3>
            <div className="bg-slate-900/30 p-8 rounded-[2rem] border border-slate-800 space-y-4">
                {history.length > 0 ? (
                    <div className="relative border-l border-slate-800 ml-4 space-y-8">
                        {history.map((h, i) => (
                            <div key={i} className="relative pl-8 group">
                                <div className="absolute -left-1.5 top-1.5 w-3 h-3 rounded-full bg-slate-700 border-2 border-slate-900 group-hover:bg-emerald-500 transition-colors"></div>
                                <div className="flex flex-col sm:flex-row sm:items-center gap-2 sm:gap-4 mb-2">
                                    <span className="text-xs font-black text-emerald-400 bg-emerald-500/10 px-2 py-1 rounded border border-emerald-500/20">{h.percentage}% Concluído</span>
                                    <span className="text-xs text-slate-500 font-bold uppercase tracking-wider">{new Date(h.date).toLocaleDateString()}</span>
                                </div>
                                <div className="bg-slate-950 p-4 rounded-xl border border-slate-800/50 space-y-2">
                                    <p className="text-sm text-slate-300"><span className="text-slate-500 font-bold uppercase text-[10px] mr-2">Feito:</span> {h.whatWasDone}</p>
                                    {h.whatIsMissing && <p className="text-sm text-slate-400"><span className="text-slate-500 font-bold uppercase text-[10px] mr-2">Pendente:</span> {h.whatIsMissing}</p>}
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <p className="text-slate-500 italic text-center py-4">Nenhum histórico de progresso registrado.</p>
                )}
            </div>
          </section>

          {r.metasPrioritarias?.length > 0 && (
          <section className="space-y-6">
            <h3 className="text-xl font-black flex items-center gap-3 text-white border-b border-slate-800 pb-4"><Target className="text-emerald-500" size={24}/> Metas Prioritárias</h3>
            <div className="bg-slate-900/20 rounded-[2rem] border border-slate-800/50 overflow-hidden">
               <table className="w-full text-left text-xs">
                 <thead className="bg-slate-900/80 text-slate-500 font-black uppercase tracking-widest border-b border-slate-800">
                   <tr>
                     <th className="p-5">Meta / Entrega</th>
                     <th className="p-5">Prazo</th>
                     <th className="p-5 text-center">Status</th>
                     <th className="p-5">Evidência</th>
                     <th className="p-5">Observação</th>
                   </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-800/30">
                   {r.metasPrioritarias?.map((m: any, i: number) => (
                     <tr key={i} className="hover:bg-slate-800/20 transition-all">
                       <td className="p-5 font-bold text-slate-100">{m.meta}</td>
                       <td className="p-5 text-emerald-400 font-bold">{m.prazo}</td>
                       <td className="p-5 text-center">
                          <div className="flex justify-center">
                             <SemaforoWithTooltip status={m.status} rules={semaforoRules} />
                          </div>
                       </td>
                       <td className="p-5">
                          {m.evidencia ? (
                             <a href={m.evidencia} target="_blank" className="flex items-center gap-1.5 text-blue-400 hover:text-blue-300 font-bold underline"><ExternalLink size={12}/> Ver Doc</a>
                          ) : <span className="text-slate-600">-</span>}
                       </td>
                       <td className="p-5 text-slate-400 italic max-w-xs truncate" title={m.obs}>{m.obs || '-'}</td>
                     </tr>
                   ))}
                 </tbody>
               </table>
            </div>
          </section>
          )}

          <div className="grid lg:grid-cols-2 gap-12">
             <div className="space-y-6">
                <h4 className="text-lg font-black text-white flex items-center gap-2 uppercase tracking-tight"><AlertTriangle className="text-amber-500" size={20}/> Problemas e Plano de Ataque</h4>
                <div className="space-y-4">
                   {r.problemasCriticos?.length > 0 ? r.problemasCriticos.map((p: any, i: number) => (
                     <div key={i} className="bg-red-500/5 border border-red-500/20 p-5 rounded-3xl space-y-3">
                        <div className="flex justify-between items-start">
                          <h6 className="font-bold text-red-400 text-sm">{p.problema}</h6>
                          <span className="text-[10px] font-black bg-red-500/20 px-2 py-0.5 rounded text-red-300 uppercase">{p.impacto} impacto</span>
                        </div>
                        <div className="p-3 bg-red-500/10 rounded-xl border border-red-500/10 text-xs">
                          <span className="text-emerald-400 font-black uppercase text-[9px] block mb-1">Ação Corretiva</span>
                          {p.acao}
                        </div>
                     </div>
                   )) : <p className="text-slate-500 italic text-sm">Nenhum problema crítico reportado.</p>}
                </div>
             </div>

             <div className="space-y-6">
                <h4 className="text-lg font-black text-white flex items-center gap-2 uppercase tracking-tight"><ShieldAlert size={20} className="text-red-500"/> Riscos e Alertas</h4>
                <div className="bg-slate-900/40 p-8 rounded-[2rem] border border-slate-800 space-y-6">
                   <div className="flex flex-wrap gap-2">
                      {['Fiscal', 'Jurídico', 'Operacional', 'Político', 'Reputacional'].map(t => (
                        <div key={t} className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase border transition-all ${r.riscos?.tipos?.includes(t) ? 'bg-red-500 text-white border-red-400 shadow-[0_0_10px_rgba(239,68,68,0.3)]' : 'bg-slate-800 text-slate-600 border-slate-700 opacity-40'}`}>{t}</div>
                      ))}
                   </div>
                   <div className="p-6 bg-slate-950 rounded-2xl border border-slate-800/80 italic text-slate-300 text-sm leading-relaxed">
                     "{r.riscos?.descricao || 'Nenhum risco crítico identificado para o período.'}"
                   </div>
                </div>
             </div>
          </div>

        </div>

        <div className="p-8 border-t border-slate-800 bg-slate-950 flex justify-between items-center text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">
           <span>Fonte Oficial: {post.fonteOficial}</span>
           <span>SGC - Monitoramento de Resultados v1.3</span>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { X, Trash2, Plus, Lock, TrendingUp, TrendingDown, Minus, History, ShieldAlert, Target, AlertTriangle, Calendar, FileText, Info, ListChecks, Clock, CheckCircle2, AlertCircle, ClipboardList, Pencil, BookOpen, AlertOctagon, GraduationCap, Link as LinkIcon, PieChart, BarChart, LineChart } from 'lucide-react';
import { ChartConfig, Post, TopicId, SemaforoConfig, ProgressUpdate, ReportSection } from '../types';
import { TOPICS } from '../constants';

interface AdminPanelProps {
  isOpen: boolean;
  onClose: () => void;
  posts: Post[];
  onAddPost: (topicId: TopicId, description: string, chartConfig: ChartConfig, extra: any) => Promise<boolean | void>;
  onEditPost: (postId: string, topicId: TopicId, description: string, chartConfig: ChartConfig, extra: any) => Promise<boolean | void>;
  onDeletePost: (postId: string) => void;
  usingServer: boolean;
}

const INITIAL_REPORT: ReportSection = {
  // Novos campos estratégicos
  objetivo: '', importanciaPrefeito: '', formula: '', acaoCrise: '',
  responsavelTecnico: '', 

  secretaria: '', periodo: '', responsavelPolitico: '', 
  pontoFocal: { nome: '', cargo: '', telefone: '', email: '' },
  resumoAvanços: '', resumoAtrasos: '', resumoDecisoes: '',
  indicadoresChave: [], metasPrioritarias: [], problemasCriticos: [], decisoesPrefeito: [],
  riscos: { tipos: [], descricao: '' }, compromissos: [], anexos: ''
};

const INITIAL_SEMAFORO: SemaforoConfig = {
  green: 'Matrículas consolidadas e validadas no sistema',
  yellow: 'Pendências de validação / risco de inconsistência',
  red: 'Matrículas não lançadas ou rejeitadas pelo sistema'
};

export const AdminPanel: React.FC<AdminPanelProps> = ({ 
  isOpen, onClose, posts, onAddPost, onEditPost, onDeletePost
}) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState('');
  const [activeTab, setActiveTab] = useState<'add' | 'list'>('add');
  const [formStep, setFormStep] = useState<number>(1);
  const [editingPostId, setEditingPostId] = useState<string | null>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [selectedTopic, setSelectedTopic] = useState<TopicId>(TopicId.EDUCACAO);
  const [responsavel, setResponsavel] = useState('');
  const [fonteOficial, setFonteOficial] = useState('');
  const [recorrencia, setRecorrencia] = useState('Mensal');

  // Novo State: Semáforo Geral e Tipo de Gráfico
  const [semaforoGeral, setSemaforoGeral] = useState<'green'|'yellow'|'red'>('green');
  const [chartType, setChartType] = useState<'bar'|'line'|'pie'>('bar');

  const [semaforoRules, setSemaforoRules] = useState<SemaforoConfig>(INITIAL_SEMAFORO);
  const [report, setReport] = useState<ReportSection>(INITIAL_REPORT);
  const [progress, setProgress] = useState(0);
  const [progressHistory, setProgressHistory] = useState<ProgressUpdate[]>([]);
  // Builder rows agora suporta cor
  const [builderRows, setBuilderRows] = useState<any[]>([{ label: 'Mês 1', Valor: 0, color: '#10b981' }]);

  // State para Nova Movimentação (Step 9)
  const [newMoveDate, setNewMoveDate] = useState(new Date().toISOString().split('T')[0]);
  const [newMovePct, setNewMovePct] = useState<number | ''>('');
  const [newMoveDone, setNewMoveDone] = useState('');
  const [newMoveMissing, setNewMoveMissing] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    const normalizedPass = passwordInput.trim().toLowerCase();
    if (normalizedPass === 'azul') setIsAuthenticated(true);
    else {
      setLoginError('Senha incorreta.');
      if (navigator.vibrate) navigator.vibrate(200);
    }
  };

  const handleEditClick = (post: Post) => {
    setEditingPostId(post.id);
    setSelectedTopic(post.topicId);
    setTitle(post.chartConfig.title);
    setDescription(post.description);
    setResponsavel(post.responsavel || '');
    setFonteOficial(post.fonteOficial || '');
    setRecorrencia(post.recorrencia || 'Mensal');
    setSemaforoRules(post.semaforoRules || INITIAL_SEMAFORO);
    setSemaforoGeral(post.semaforoGeral || 'green');
    setChartType(post.chartConfig.type || 'bar');

    setReport({ ...INITIAL_REPORT, ...post.report });
    setProgress(post.progress || 0);
    setProgressHistory(post.progressHistory || []);
    setBuilderRows(Array.isArray(post.chartConfig.data) ? post.chartConfig.data : []);

    setActiveTab('add');
    setFormStep(1);
  };

  const handleSubmit = async () => {
    // Monta o config do gráfico com as cores individuais
    const config: ChartConfig = { 
        type: chartType, 
        title, 
        data: builderRows // rows já contém {label, Valor, color}
    };

    const finalReport = {
      ...report,
      responsavelPolitico: responsavel,
    };

    const extra = { 
        responsavel, 
        fonteOficial, 
        recorrencia, 
        dataAtualizacao: Date.now(), 
        semaforoRules, 
        semaforoGeral, // Salva o status geral
        progress, 
        progressHistory, 
        report: finalReport 
    };

    let success;
    if (editingPostId) success = await onEditPost(editingPostId, selectedTopic, description, config, extra);
    else success = await onAddPost(selectedTopic, description, config, extra);

    if (success !== false) {
      setEditingPostId(null); setTitle(''); setReport(INITIAL_REPORT); setActiveTab('list');
      setBuilderRows([{ label: 'Mês 1', Valor: 0, color: '#10b981' }]); 
      setProgress(0); setProgressHistory([]);
    }
  };

  const addProgressMove = () => {
    if (newMovePct === '') return;
    const dateObj = new Date(newMoveDate);
    const utcDate = new Date(dateObj.valueOf() + dateObj.getTimezoneOffset() * 60000).getTime();

    const update: ProgressUpdate = {
      date: utcDate,
      percentage: Number(newMovePct),
      whatWasDone: newMoveDone,
      whatIsMissing: newMoveMissing
    };
    setProgress(Number(newMovePct));
    setProgressHistory([update, ...progressHistory]);
    setNewMovePct('');
    setNewMoveDone('');
    setNewMoveMissing('');
  };

  if (!isAuthenticated) {
    return (
      <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-4">
        <div className="bg-slate-900 border border-slate-700 rounded-3xl p-8 md:p-12 w-full max-w-sm text-center space-y-8 shadow-2xl">
          <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mx-auto border border-emerald-500/20"><Lock className="text-emerald-400" size={32}/></div>
          <h2 className="text-2xl font-black text-white uppercase tracking-tighter">Gestão Técnica</h2>
          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <input type="password" value={passwordInput} onChange={e => { setPasswordInput(e.target.value); setLoginError(''); }} placeholder="Senha" className={`w-full p-4 bg-slate-950 border ${loginError ? 'border-red-500' : 'border-slate-800'} rounded-2xl text-white text-center font-black outline-none focus:ring-2 focus:ring-emerald-500`} autoFocus />
              {loginError && <p className="text-red-400 text-xs font-bold mt-2">{loginError}</p>}
            </div>
            <button type="submit" className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase hover:bg-emerald-500 transition-all">Acessar</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4">
      <div className="bg-[#0f172a] border border-slate-800 rounded-[2rem] w-full max-w-6xl h-[95vh] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">

        <div className="p-6 border-b border-slate-800 bg-slate-900/50 flex justify-between items-center">
          <div className="flex items-center gap-8">
            <h2 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-2"><ClipboardList className="text-emerald-500" /> Sala de Lançamento</h2>
            <div className="flex bg-slate-800/50 p-1.5 rounded-2xl">
              <button onClick={() => setActiveTab('add')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase transition-all ${activeTab === 'add' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white'}`}>{editingPostId ? 'Editar' : 'Novo'}</button>
              <button onClick={() => setActiveTab('list')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase transition-all ${activeTab === 'list' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white'}`}>Catálogo</button>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-500"><X size={24}/></button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {activeTab === 'add' && (
            <div className="w-64 bg-slate-900/30 border-r border-slate-800 p-6 flex flex-col gap-2 overflow-y-auto hidden md:flex">
              {[
                { id: 1, label: '1. Definição', icon: BookOpen },
                { id: 2, label: '2. Semáforo', icon: AlertOctagon },
                { id: 3, label: '3. Dados & Gráfico', icon: TrendingUp },
                { id: 4, label: '4. Resumo Exec.', icon: FileText },
                { id: 5, label: '5. Informações', icon: ListChecks }, // Nome alterado
                { id: 6, label: '6. Metas Priorit.', icon: Target },
                { id: 7, label: '7. Prob. & Decisões', icon: AlertTriangle },
                { id: 8, label: '8. Riscos', icon: ShieldAlert },
                { id: 9, label: '9. Histórico', icon: History },
              ].map(step => (
                <button key={step.id} onClick={() => setFormStep(step.id)} className={`flex items-center gap-3 p-3.5 rounded-xl text-[10px] font-black uppercase tracking-widest text-left transition-all ${formStep === step.id ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'text-slate-500 hover:text-slate-300'}`}>
                  <step.icon size={16} className={formStep === step.id ? 'text-emerald-400' : 'text-slate-600'} />
                  {step.label}
                </button>
              ))}
              <div className="mt-auto pt-6 border-t border-slate-800">
                <button onClick={handleSubmit} className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black uppercase rounded-2xl shadow-xl transition-all active:scale-95">Salvar</button>
              </div>
            </div>
          )}

          <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
            {activeTab === 'add' ? (
              <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in duration-500">

                {/* Passo 1 - Mantido */}
                {formStep === 1 && (
                  <div className="space-y-8">
                    <h3 className="text-2xl font-black text-white border-b border-slate-800 pb-4">1. Definição Estratégica</h3>
                    <div className="grid md:grid-cols-2 gap-6">
                       <div className="space-y-2">
                         <label className="text-[10px] font-black text-slate-500 uppercase">Nome do Indicador</label>
                         <input value={title} onChange={e => setTitle(e.target.value)} className="w-full p-4 bg-slate-900 border border-slate-800 rounded-2xl text-white font-bold" />
                       </div>
                       <div className="space-y-2">
                         <label className="text-[10px] font-black text-slate-500 uppercase">Área</label>
                         <select value={selectedTopic} onChange={e => setSelectedTopic(e.target.value as TopicId)} className="w-full p-4 bg-slate-900 border border-slate-800 rounded-2xl text-white font-bold">
                            {TOPICS.map(t => <option key={t.id} value={t.id}>{t.label}</option>)}
                         </select>
                       </div>
                    </div>

                    {/* Seletor de Status Geral */}
                    <div className="p-6 bg-slate-900 border border-slate-800 rounded-2xl space-y-3">
                         <label className="text-[10px] font-black text-slate-500 uppercase">Status Geral do Indicador (Aparece na Lista)</label>
                         <div className="flex gap-4">
                            {(['green', 'yellow', 'red'] as const).map(color => (
                                <button
                                    key={color}
                                    onClick={() => setSemaforoGeral(color)}
                                    className={`flex-1 p-4 rounded-xl border-2 transition-all flex items-center justify-center gap-2 ${semaforoGeral === color 
                                        ? (color === 'green' ? 'border-emerald-500 bg-emerald-500/20 text-emerald-400' : color === 'yellow' ? 'border-amber-500 bg-amber-500/20 text-amber-400' : 'border-red-500 bg-red-500/20 text-red-400') 
                                        : 'border-slate-800 bg-slate-950 text-slate-600 hover:border-slate-700'}`}
                                >
                                    <div className={`w-3 h-3 rounded-full ${color === 'green' ? 'bg-emerald-500' : color === 'yellow' ? 'bg-amber-500' : 'bg-red-500'}`} />
                                    <span className="font-bold uppercase text-xs">{color === 'green' ? 'Normal' : color === 'yellow' ? 'Atenção' : 'Crítico'}</span>
                                </button>
                            ))}
                         </div>
                    </div>

                    <div className="space-y-2">
