ed-xl"><CheckCircle2 size={16}/></button><button onClick={() => setIsAddingCustomRisk(false)} className="p-2.5 bg-slate-800 text-slate-400 hover:text-white rounded-xl"><X size={16}/></button></div>)}</div></div><textarea value={report.riscos.descricao} onChange={e => setReport({...report, riscos: {...report.riscos, descricao: e.target.value}})} className="w-full p-6 bg-slate-950 border border-slate-800 rounded-3xl text-white text-sm" placeholder="Descreva..." h-40 /></div></div>)}
                {formStep === 9 && (<div className="space-y-8 text-center max-w-xl mx-auto"><h3 className="text-2xl font-black text-white border-b border-slate-800 pb-4">9. Atualizar Evolução</h3><div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800 shadow-2xl space-y-6 text-left"><div className="grid grid-cols-2 gap-4"><div><label className="text-[10px] font-black text-slate-500 uppercase block mb-2">Data</label><input type="date" value={newMoveDate} onChange={e => setNewMoveDate(e.target.value)} className="w-full p-3 bg-slate-950 border border-slate-800 rounded-xl text-white font-bold" /></div><div><label className="text-[10px] font-black text-slate-500 uppercase block mb-2">%</label><input type="number" min="0" max="100" value={newMovePct} onChange={e => setNewMovePct(Number(e.target.value))} className="w-full p-3 bg-slate-950 border border-slate-800 rounded-xl text-emerald-400 font-black text-xl text-center" /></div></div><div className="space-y-4"><div><label className="text-[10px] font-black text-slate-500 uppercase block mb-1">Feito</label><input value={newMoveDone} onChange={e => setNewMoveDone(e.target.value)} className="w-full p-3 bg-slate-950 border border-slate-800 rounded-xl text-white text-sm" /></div><div><label className="text-[10px] font-black text-slate-500 uppercase block mb-1">Pendências</label><input value={newMoveMissing} onChange={e => setNewMoveMissing(e.target.value)} className="w-full p-3 bg-slate-950 border border-slate-800 rounded-xl text-white text-sm" /></div></div><button onClick={addProgressMove} disabled={newMovePct === ''} className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 text-white font-black uppercase rounded-2xl shadow-xl hover:-translate-y-1 transition-all flex items-center justify-center gap-2"><Plus size={18}/> Registrar</button></div><div className="space-y-4 text-left">{progressHistory.map((up, i) => (<div key={i} className="p-5 bg-slate-900/50 border border-slate-800 rounded-2xl flex justify-between items-center group"><div><div className="text-emerald-400 font-black text-xs flex items-center gap-2"><span className="bg-emerald-500/10 px-2 py-0.5 rounded border border-emerald-500/20">{up.percentage}%</span> <span className="text-white">[{new Date(up.date).toLocaleDateString()}]</span></div><p className="text-xs text-slate-300 mt-2">{up.whatWasDone}</p></div><button onClick={() => setProgressHistory(progressHistory.filter((_, idx) => idx !== i))} className="p-2 text-slate-700 hover:text-red-500 opacity-0 group-hover:opacity-100"><Trash2 size={16}/></button></div>))}</div></div>)}

              </div>
            ) : (
