                        <div className="bg-slate-900 border border-slate-800 rounded-3xl overflow-hidden shadow-2xl">
                        <table className="w-full text-xs text-left">
                            <thead className="bg-slate-950 text-slate-500 font-black uppercase">
                            <tr><th className="p-4">Tema</th><th className="p-4">Decisão</th><th className="p-4"></th></tr>
                            </thead>
                            <tbody className="divide-y divide-slate-800">
                            {report.decisoesPrefeito.map((d, i) => (
                                <tr key={i}>
                                <td className="p-2"><input value={d.tema} onChange={e => { const n = [...report.decisoesPrefeito]; n[i].tema = e.target.value; setReport({...report, decisoesPrefeito: n}); }} className="w-full bg-transparent p-2 text-white outline-none" placeholder="Tema" /></td>
                                <td className="p-2"><input value={d.decisao} onChange={e => { const n = [...report.decisoesPrefeito]; n[i].decisao = e.target.value; setReport({...report, decisoesPrefeito: n}); }} className="w-full bg-transparent p-2 text-white outline-none" placeholder="Decisão" /></td>
                                <td className="p-2"><button onClick={() => setReport({...report, decisoesPrefeito: report.decisoesPrefeito.filter((_, idx) => idx !== i)})} className="text-slate-600 hover:text-red-500"><Trash2 size={14}/></button></td>
                                </tr>
                            ))}
                            </tbody>
                        </table>
                        <button onClick={() => setReport({...report, decisoesPrefeito: [...report.decisoesPrefeito, {tema: '', decisao: '', consequencia: '', prazo: ''}]})} className="w-full p-4 bg-slate-800 text-xs font-black uppercase text-emerald-400 hover:bg-slate-700 transition-all">+ Decisão</button>
                        </div>
                    </div>
                  </div>
                )}
                {formStep === 8 && (
                   <div className="space-y-10">
                      <h3 className="text-2xl font-black text-white border-b border-slate-800 pb-4">8. Riscos</h3>
                      <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 space-y-8 shadow-2xl">
                         <div className="space-y-4">
                            <div className="flex flex-wrap gap-3">
                               {['Fiscal', 'Jurídico', 'Operacional', 'Político', 'Reputacional'].map(t => (
                                 <button key={t} onClick={() => { const n = report.riscos.tipos.includes(t) ? report.riscos.tipos.filter(x => x !== t) : [...report.riscos.tipos, t]; setReport({...report, riscos: {...report.riscos, tipos: n}}); }} className={`px-5 py-3 rounded-2xl text-[10px] font-black uppercase border transition-all ${report.riscos.tipos.includes(t) ? 'bg-red-600 border-red-500 text-white' : 'bg-slate-950 border-slate-800 text-slate-600'}`}>{t}</button>
                               ))}
                               {report.riscos.tipos.filter(t => !['Fiscal', 'Jurídico', 'Operacional', 'Político', 'Reputacional'].includes(t)).map(t => (
                                   <button key={t} onClick={() => { const n = report.riscos.tipos.filter(x => x !== t); setReport({...report, riscos: {...report.riscos, tipos: n}}); }} className="px-5 py-3 rounded-2xl text-[10px] font-black uppercase border bg-red-600 border-red-500 text-white flex items-center gap-2">
                                       {t} <X size={12}/>
                                   </button>
                               ))}

                               {!isAddingCustomRisk ? (
                                   <button onClick={() => setIsAddingCustomRisk(true)} className="px-5 py-3 rounded-2xl text-[10px] font-black uppercase border border-slate-700 bg-slate-900 text-slate-400 hover:bg-slate-800 transition-all flex items-center gap-2">
                                       Outros +
                                   </button>
                               ) : (
                                   <div className="flex items-center gap-2">
                                       <input 
                                           value={customRiskInput} 
                                           onChange={e => setCustomRiskInput(e.target.value)} 
                                           className="px-4 py-2.5 rounded-xl text-xs bg-slate-950 border border-slate-700 text-white outline-none focus:border-emerald-500"
                                           placeholder="Digite o risco..."
                                           autoFocus
                                           onKeyDown={e => e.key === 'Enter' && addCustomRisk()}
                                       />
                                       <button onClick={addCustomRisk} className="p-2.5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-xl"><CheckCircle2 size={16}/></button>
                                       <button onClick={() => setIsAddingCustomRisk(false)} className="p-2.5 bg-slate-800 text-slate-400 hover:text-white rounded-xl"><X size={16}/></button>
                                   </div>
                               )}
                            </div>
                         </div>
                         <textarea value={report.riscos.descricao} onChange={e => setReport({...report, riscos: {...report.riscos, descricao: e.target.value}})} className="w-full p-6 bg-slate-950 border border-slate-800 rounded-3xl text-white text-sm" placeholder="Descreva..." h-40 />
                      </div>
                   </div>
                )}
                {formStep === 9 && (
                   <div className="space-y-8 text-center max-w-xl mx-auto">
                      <h3 className="text-2xl font-black text-white border-b border-slate-800 pb-4">9. Atualizar Evolução</h3>
                      <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800 shadow-2xl space-y-6 text-left">
                         <div className="grid grid-cols-2 gap-4">
                             <div><label className="text-[10px] font-black text-slate-500 uppercase block mb-2">Data</label><input type="date" value={newMoveDate} onChange={e => setNewMoveDate(e.target.value)} className="w-full p-3 bg-slate-950 border border-slate-800 rounded-xl text-white font-bold" /></div>
                             <div><label className="text-[10px] font-black text-slate-500 uppercase block mb-2">%</label><input type="number" min="0" max="100" value={newMovePct} onChange={e => setNewMovePct(Number(e.target.value))} className="w-full p-3 bg-slate-950 border border-slate-800 rounded-xl text-emerald-400 font-black text-xl text-center" /></div>
                         </div>
                         <div className="space-y-4">
                            <div><label className="text-[10px] font-black text-slate-500 uppercase block mb-1">Feito</label><input value={newMoveDone} onChange={e => setNewMoveDone(e.target.value)} className="w-full p-3 bg-slate-950 border border-slate-800 rounded-xl text-white text-sm" /></div>
                            <div><label className="text-[10px] font-black text-slate-500 uppercase block mb-1">Pendências</label><input value={newMoveMissing} onChange={e => setNewMoveMissing(e.target.value)} className="w-full p-3 bg-slate-950 border border-slate-800 rounded-xl text-white text-sm" /></div>
                         </div>
                         <button onClick={addProgressMove} disabled={newMovePct === ''} className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-50 text-white font-black uppercase rounded-2xl shadow-xl hover:-translate-y-1 transition-all flex items-center justify-center gap-2"><Plus size={18}/> Registrar</button>
                      </div>
                      <div className="space-y-4 text-left">
                        {progressHistory.map((up, i) => (
                            <div key={i} className="p-5 bg-slate-900/50 border border-slate-800 rounded-2xl flex justify-between items-center group">
                              <div><div className="text-emerald-400 font-black text-xs flex items-center gap-2"><span className="bg-emerald-500/10 px-2 py-0.5 rounded border border-emerald-500/20">{up.percentage}%</span> <span className="text-white">[{new Date(up.date).toLocaleDateString()}]</span></div><p className="text-xs text-slate-300 mt-2">{up.whatWasDone}</p></div>
                              <button onClick={() => setProgressHistory(progressHistory.filter((_, idx) => idx !== i))} className="p-2 text-slate-700 hover:text-red-500 opacity-0 group-hover:opacity-100"><Trash2 size={16}/></button>
                            </div>
                        ))}
                      </div>
                   </div>
                )}
              </div>
            ) : (
              // Modo Lista (Catálogo)
              <div className="space-y-6">
                <div className="flex justify-between items-end mb-6 px-4">
                    <div>
                         <h3 className="text-2xl font-black text-white">Catálogo</h3>
                         <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">{filteredPosts.length} Cadastrados</p>
                    </div>

                    <div className="flex items-center gap-3">
                        <div className="relative">
                            <select 
                                value={filterTopic} 
                                onChange={e => setFilterTopic(e.target.value)}
                                className="appearance-none bg-slate-900 text-white text-xs font-bold uppercase pl-10 pr-8 py-2.5 rounded-xl border border-slate-700 focus:border-emerald-500 outline-none cursor-pointer hover:bg-slate-800 transition-colors"
                            >
                                <option value="all">Todas as Áreas</option>
                                {TOPICS.map(t => <option key={t.id} value={t.id}>{t.label}</option>)}
                            </select>
                            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={14}/>
                            <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none border-t-4 border-l-4 border-r-4 border-transparent border-t-slate-500"></div>
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-1 gap-4">
                  {filteredPosts.map((post, index) => (
                    <div 
                        key={post.id} 
                        className={`bg-slate-900/40 p-6 rounded-3xl border flex items-center justify-between group transition-all ${isDragging ? 'opacity-50 border-dashed border-slate-700' : 'border-slate-800 hover:border-emerald-500/30'}`}
                        draggable
                        onDragStart={() => { dragItem.current = index; setIsDragging(true); }}
                        onDragEnter={() => { dragOverItem.current = index; }}
                        onDragEnd={handleSort}
                        onDragOver={(e) => e.preventDefault()}
                    >
                      <div className="flex items-center gap-6">
                         {/* Grip Handle for Dragging */}
                         <div className="p-2 rounded cursor-grab active:cursor-grabbing text-slate-600 hover:text-white">
                             <GripVertical size={20} />
                         </div>

                        <div className="w-14 h-14 bg-slate-950 rounded-2xl flex items-center justify-center border border-slate-800 group-hover:scale-105 transition-all relative">
                          <span className="text-[10px] font-black text-slate-600">{post.topicId.substring(0,3).toUpperCase()}</span>
                          <div className={`absolute -top-1 -right-1 w-4 h-4 rounded-full border-2 border-slate-900 ${post.semaforoGeral === 'yellow' ? 'bg-amber-500' : post.semaforoGeral === 'red' ? 'bg-red-500' : 'bg-emerald-500'}`}></div>
                        </div>
                        <div>
                          <h4 className="font-black text-slate-100 text-lg leading-none mb-1">{post.chartConfig.title}</h4>
                          <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{post.responsavel} • {new Date(post.dataAtualizacao).toLocaleDateString()}</p>
                        </div>
                      </div>
                      <div className="flex items-center gap-4">
                        <button onClick={() => handleEditClick(post)} className="p-3 bg-blue-500/10 text-blue-400 hover:bg-blue-500 hover:text-white rounded-xl transition-all"><Pencil size={18}/></button>
                        <button onClick={() => onDeletePost(post.id)} className="p-3 bg-red-500/10 text-red-400 hover:bg-red-500 hover:text-white rounded-xl transition-all"><Trash2 size={18}/></button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  LineChart,
  Line,
  PieChart,
  Pie,
  Cell,
  ComposedChart
} from 'recharts';
import { ChartConfig, ExternalChartData } from '../types';

interface ChartRendererProps {
  config: ChartConfig;
}

const COLORS = ['#0ea5e9', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#6366f1'];

const formatValue = (value: number) => {
    return new Intl.NumberFormat('pt-BR', { maximumFractionDigits: 2 }).format(value);
};

export const ChartRenderer: React.FC<ChartRendererProps> = ({ config }) => {
  const { type, color: mainColor } = config;

  const { processedData, dataKeys, isComplex, complexConfig } = useMemo(() => {
    try {
      // CASO 0: Formato Complexo
      if (config.data && !Array.isArray(config.data) && typeof config.data === 'object') {
        const extData = config.data as any; 

        if ('labels' in extData || 'series' in extData) {
          const labels = Array.isArray(extData.labels) ? extData.labels : [];
          const series = Array.isArray(extData.series) ? extData.series : [];

          const normalized = labels.map((label: string, index: number) => {
            const item: any = { label };
            series.forEach((s: any, sIndex: number) => {
              if (!s) return;
              const key = s.name || s.label || `series_${sIndex}`;
              const val = (Array.isArray(s.data) && s.data[index] !== undefined) ? s.data[index] : null;
              item[key] = val;
            });
            return item;
          });

          const keys = series
            .filter((s: any) => s)
            .map((s: any) => s.name || s.label || 'unknown');

          return {
            processedData: normalized,
            dataKeys: keys,
            isComplex: true,
            complexConfig: extData as ExternalChartData
          };
        }
      }

      // CASO 1: Formato "Nested Values"
      if (config.data && Array.isArray(config.data) && config.data.length > 0) {
        const firstItem = config.data[0];
        if (firstItem && 'values' in firstItem && Array.isArray(firstItem.values)) {
          const seriesList = config.data as any[];
          const uniqueLabels = new Set<string>();

          seriesList.forEach(series => {
            if (Array.isArray(series.values)) {
              series.values.forEach((v: any) => {
                const xAxisLabel = v.city || v.label;
                if (xAxisLabel) uniqueLabels.add(xAxisLabel);
              });
            }
          });

          const normalized = Array.from(uniqueLabels).map(xAxisLabel => {
            const row: any = { label: xAxisLabel };
            seriesList.forEach(series => {
              const seriesName = series.label || series.name || 'Unnamed';
              const point = series.values?.find((v: any) => (v.city || v.label) === xAxisLabel);
              if (point) {
                row[seriesName] = point.value;
              }
            });
            return row;
          });

          const keys = seriesList.map(s => s.label || s.name || 'Unknown');

          return { processedData: normalized, dataKeys: keys, isComplex: false };
        }
      }

      // CASO 2: Formato "Series" (Antigo)
      if (config.series && Array.isArray(config.series)) {
        const allLabels = new Set<string>();
        config.series.forEach(s => s.data.forEach(d => allLabels.add(d.label)));

        const normalized = Array.from(allLabels).map(label => {
          const item: any = { label };
          config.series?.forEach(s => {
            const point = s.data.find(d => d.label === label);
            if (point) {
              item[s.name] = point.value;
            }
          });
          return item;
        });

        return {
          processedData: normalized,
          dataKeys: config.series.map(s => s.name),
          isComplex: false
        };
      }

      // CASO 3: Formato "Flat" (Simples & Novo AdminPanel)
      if (config.data && Array.isArray(config.data) && config.data.length > 0) {
        const first = config.data[0];
        if (!('values' in first) && !('series' in first)) {
          // Detecta se tem chaves especiais (barValue/lineValue)
          if (first.barValue !== undefined || first.lineValue !== undefined) {
               return { processedData: config.data, dataKeys: ['barValue', 'lineValue'], isComplex: false };
          }

          const keys = Object.keys(first).filter(k => k !== 'label' && k !== 'city' && k !== 'color');
          const normalized = config.data.map((item: any) => ({
            ...item,
            label: item.label || item.city || 'Unknown'
          }));

          return { processedData: normalized, dataKeys: keys, isComplex: false };
        }
      }

      return { processedData: [], dataKeys: [], isComplex: false };

    } catch (e) {
      console.error("Erro ao processar dados do gráfico:", e);
      return { processedData: [], dataKeys: [], isComplex: false };
    }
  }, [config]);

  const renderChart = () => {
    if (!processedData || processedData.length === 0) {
      return (
        <div className="flex items-center justify-center h-full text-slate-500 text-sm">
          Sem dados para exibir
        </div>
      );
    }

    const commonMargin = { top: 40, right: 20, bottom: 5, left: 0 };
    const domainWithPadding: [number, any] = [0, (dataMax: number) => Math.ceil(dataMax * 1.1)];

    // NOVO: Detecta se é o formato misto do novo AdminPanel (com barValue e lineValue)
    if (processedData.length > 0 && (processedData[0].barValue !== undefined || processedData[0].lineValue !== undefined)) {
        return (
            <ComposedChart data={processedData} margin={commonMargin}>
              <CartesianGrid stroke="#334155" strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="label" scale="point" padding={{ left: 20, right: 20 }} stroke="#94a3b8" fontSize={11} tickLine={false} />
              <YAxis stroke="#94a3b8" fontSize={11} tickLine={false} domain={domainWithPadding} tickFormatter={formatValue} />
              <Tooltip formatter={(value: number) => [formatValue(value), '']} contentStyle={{ backgroundColor: '#1e293b', borderRadius: '8px', border: '1px solid #334155', color: '#f8fafc' }} />
              <Legend wrapperStyle={{ paddingTop: '10px' }} />

              <Bar dataKey="barValue" name="Valor (Barra)" radius={[4, 4, 0, 0]} barSize={40}>
                 {processedData.map((entry: any, i: number) => (
                  <Cell key={`cell-${i}`} fill={entry.color || '#10b981'} />
                ))}
              </Bar>
              <Line type="monotone" dataKey="lineValue" name="Meta (Linha)" stroke="#f59e0b" strokeWidth={3} dot={{ r: 4 }} activeDot={{ r: 6 }} />
            </ComposedChart>
        );
    }

    if (isComplex && complexConfig && complexConfig.series) {
      // ... (Código complexo anterior mantido) ...
      return (
        <ComposedChart data={processedData} margin={commonMargin}>
          <CartesianGrid stroke="#334155" strokeDasharray="3 3" vertical={false} />
          <XAxis dataKey="label" scale="point" padding={{ left: 10, right: 10 }} stroke="#94a3b8" fontSize={11} tickLine={false} />
          <YAxis yAxisId="left" orientation="left" stroke="#94a3b8" fontSize={11} tickLine={false} domain={domainWithPadding} label={complexConfig.yAxes?.left?.title ? { value: complexConfig.yAxes.left.title, angle: -90, position: 'insideLeft', fill: '#94a3b8', fontSize: 10 } : undefined} />
          <YAxis yAxisId="right" orientation="right" stroke="#94a3b8" fontSize={11} tickLine={false} hide={!complexConfig.yAxes?.right} domain={domainWithPadding} label={complexConfig.yAxes?.right?.title ? { value: complexConfig.yAxes.right.title, angle: 90, position: 'insideRight', fill: '#94a3b8', fontSize: 10 } : undefined} />
          <Tooltip formatter={(value: number) => [formatValue(value), '']} contentStyle={{ backgroundColor: '#1e293b', borderRadius: '8px', border: '1px solid #334155', color: '#f8fafc' }} />
          <Legend wrapperStyle={{ paddingTop: '10px' }} />
          {complexConfig.series.map((serie, index) => {
            if (!serie) return null; 
            const serieColor = serie.color || COLORS[index % COLORS.length];
            const yAxisId = serie.yAxis === 'right' ? 'right' : 'left';
            const dataKey = serie.name || serie.label || `series_${index}`;
            if (serie.type === 'line') {
              return <Line key={dataKey} type="monotone" dataKey={dataKey} name={dataKey} stroke={serieColor} strokeWidth={3} yAxisId={yAxisId} dot={{ r: 4 }} activeDot={{ r: 6 }} />;
            } else {
              return <Bar key={dataKey} dataKey={dataKey} name={dataKey} fill={serieColor} yAxisId={yAxisId} radius={[4, 4, 0, 0]} barSize={40} />;
            }
          })}
        </ComposedChart>
      );
    }

    switch (type) {
      case 'line':
        return (
          <LineChart data={processedData} margin={commonMargin}>
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
            <XAxis dataKey="label" stroke="#94a3b8" fontSize={12} tickLine={false} />
            <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} domain={domainWithPadding} tickFormatter={formatValue} />
            <Tooltip formatter={(value: number) => [formatValue(value), '']} contentStyle={{ backgroundColor: '#1e293b', borderRadius: '8px', border: '1px solid #334155', color: '#f8fafc' }} itemStyle={{ color: '#e2e8f0' }} />
            <Legend wrapperStyle={{ paddingTop: '10px' }} />
            {dataKeys.map((key, index) => (
              <Line key={key} type="monotone" dataKey={key} name={key === 'value' ? 'Valor' : key} stroke={COLORS[index % COLORS.length]} strokeWidth={3} activeDot={{ r: 6 }} />
            ))}
          </LineChart>
        );
      case 'pie':
        const pieDataKey = dataKeys[0] || 'value';
        return (
          <PieChart>
             <Pie
              data={processedData}
              cx="50%"
              cy="50%"
              labelLine={false}
              label={({ cx, cy, midAngle, innerRadius, outerRadius, percent }) => {
                const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
                const x = cx + radius * Math.cos(-midAngle * Math.PI / 180);
                const y = cy + radius * Math.sin(-midAngle * Math.PI / 180);
                return percent > 0.05 ? (
                  <text x={x} y={y} fill="white" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" fontSize={12}>
                    {`${(percent * 100).toFixed(0)}%`}
                  </text>
                ) : null;
              }}
              outerRadius={80}
              dataKey={pieDataKey}
              nameKey="label"
            >
              {processedData.map((entry: any, index: number) => (
                <Cell key={`cell-${index}`} fill={entry.color || COLORS[index % COLORS.length]} stroke="rgba(0,0,0,0.2)" />
              ))}
            </Pie>
            <Tooltip formatter={(value: number) => [formatValue(value), '']} contentStyle={{ backgroundColor: '#1e293b', borderRadius: '8px', border: '1px solid #334155', color: '#f8fafc' }} />
            <Legend />
          </PieChart>
        );
      case 'bar':
      default:
        return (
          <BarChart data={processedData} margin={commonMargin}>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#334155" />
            <XAxis dataKey="label" stroke="#94a3b8" fontSize={12} tickLine={false} />
            <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} domain={domainWithPadding} tickFormatter={formatValue} />
            <Tooltip formatter={(value: number) => [formatValue(value), '']} cursor={{ fill: '#334155', opacity: 0.4 }} contentStyle={{ backgroundColor: '#1e293b', borderRadius: '8px', border: '1px solid #334155', color: '#f8fafc' }} itemStyle={{ color: '#e2e8f0' }} />
            <Legend wrapperStyle={{ paddingTop: '10px' }} />
            {dataKeys.map((key, index) => (
              <Bar key={key} dataKey={key} name={key === 'value' ? 'Quantidade' : key} fill={dataKeys.length === 1 && mainColor ? mainColor : COLORS[index % COLORS.length]} radius={[4, 4, 0, 0]}>
                {processedData.map((entry: any, i: number) => (
                  <Cell key={`cell-${i}`} fill={entry.color || (dataKeys.length === 1 && mainColor ? mainColor : COLORS[index % COLORS.length])} />
                ))}
              </Bar>
            ))}
          </BarChart>
        );
    }
  };

  return (
    <div className="w-full h-full min-h-[300px]">
      <ResponsiveContainer width="100%" height="100%">
        {renderChart()}
      </ResponsiveContainer>
    </div>
  );
};

export enum TopicId {
  SAUDE = 'saude',
  EDUCACAO = 'educacao',
  DESENVOLVIMENTO_SOCIAL = 'social',
  FINANCAS = 'financas',
  ESPORTE_CULTURA_LAZER = 'esporte',
  AGRICULTURA = 'agricultura',
  INFRAESTRUTURA = 'infraestrutura',
  PLANEJAMENTO = 'planejamento',
}

export interface ProgressUpdate {
  date: number;
  percentage: number;
  whatWasDone: string;
  whatIsMissing: string;
}

export interface SemaforoConfig {
  green: string;
  yellow: string;
  red: string;
}

export interface ReportSection {
  // 1. Identificação & Estratégia
  objetivo: string;
  importanciaPrefeito: string;
  formula: string;
  acaoCrise: string; // Ação automática se RED

  secretaria: string;
  periodo: string;
  responsavelPolitico: string;
  responsavelTecnico: string;
  pontoFocal: {
    nome: string;
    cargo: string;
    telefone: string;
    email: string;
  };

  // 2. Resumo Executivo
  resumoAvanços: string;
  resumoAtrasos: string;
  resumoDecisoes: string;

  // 3. Dados do Gráfico (Gerenciado via ChartConfig, mas referenciado aqui logicamente)

  // 5. Informações do Indicador (Antigo Indicadores Secundários)
  // Campos: Resultado atual, Meta (trimestre/ano), Sinal (🟢/🟡/🔴), Tendência (↑/→/↓) e Fonte do dado
  indicadoresChave: Array<{
    nome: string; // Nome do indicador/Variável
    resultado: string;
    meta: string;
    status: 'green' | 'yellow' | 'red'; // Sinal
    tendencia: 'up' | 'stable' | 'down';
    fonte: string;
  }>;

  // 6. Metas Prioritárias
  metasPrioritarias: Array<{
    meta: string;
    prazo: string;
    responsavel: string;
    status: 'green' | 'yellow' | 'red';
    evidencia: string; // Link/Foto/SEI
    obs: string; // Observação objetiva
  }>;

  // 7. Problemas Críticos
  problemasCriticos: Array<{
    problema: string;
    impacto: 'Alto' | 'Médio' | 'Baixo';
    causa: string;
    acao: string;
    prazo: string;
  }>;

  // 6. Decisões Prefeito (Mantido no index 7 logicamente ou grupo de problemas)
  decisoesPrefeito: Array<{
    tema: string;
    decisao: string;
    consequencia: string;
    prazo: string;
  }>;

  // 8. Riscos e Alertas
  riscos: {
    tipos: string[];
    descricao: string;
  };

  // 9. Compromissos Próximo Período
  compromissos: Array<{
    compromisso: string;
    prazo: string;
    responsavel: string;
    evidencia: string;
  }>;

  // 10. Anexos
  anexos: string;
}

