    if (type === 'down') {
        return (
            <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-red-500/10 border border-red-500/20 text-red-400 font-bold text-[10px] uppercase tracking-wide">
                <TrendingDown size={14} /> Queda
