      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {topicPosts.map(post => {
            const status = post.semaforoGeral || 'green';
            const rules = post.semaforoRules || { green: 'Normal', yellow: 'Atenção', red: 'Crítico' };
