                     <div key={i} className="bg-red-500/5 border border-red-500/20 p-5 rounded-3xl space-y-4">
                        <div className="flex justify-between items-start">
                          <h6 className="font-bold text-red-400 text-sm">{p.problema}</h6>
                          <span className={`text-[10px] font-black px-2 py-0.5 rounded uppercase ${p.impacto === 'Alto' ? 'bg-red-500/20 text-red-300' : 'bg-amber-500/20 text-amber-300'}`}>{p.impacto} impacto</span>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                               <span className="text-slate-500 font-black uppercase text-[9px] block mb-1">Causa Provável</span>
                               <p className="text-xs text-slate-300">{p.causa || '-'}</p>
                            </div>
                            <div>
                               <span className="text-slate-500 font-black uppercase text-[9px] block mb-1">Prazo</span>
                               <p className="text-xs text-slate-300">{p.prazo || '-'}</p>
                            </div>
                        </div>

                        <div className="p-3 bg-red-500/10 rounded-xl border border-red-500/10 text-xs">
                          <span className="text-emerald-400 font-black uppercase text-[9px] block mb-1">Ação Corretiva</span>
                          {p.acao}
                        </div>
                     </div>
                   )) : <p className="text-slate-500 italic text-sm">Nenhum problema crítico reportado.</p>}
                </div>
             </div>

             <div className="space-y-6">
                <h4 className="text-lg font-black text-white flex items-center gap-2 uppercase tracking-tight"><ShieldAlert size={20} className="text-red-500"/> Riscos e Alertas</h4>
                <div className="bg-slate-900/40 p-8 rounded-[2rem] border border-slate-800 space-y-6">
                   <div className="flex flex-wrap gap-2">
                      {['Fiscal', 'Jurídico', 'Operacional', 'Político', 'Reputacional'].map(t => (
                        <div key={t} className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase border transition-all ${r.riscos?.tipos?.includes(t) ? 'bg-red-500 text-white border-red-400 shadow-[0_0_10px_rgba(239,68,68,0.3)]' : 'bg-slate-800 text-slate-600 border-slate-700 opacity-40'}`}>{t}</div>
                      ))}
                   </div>
                   <div className="p-6 bg-slate-950 rounded-2xl border border-slate-800/80 italic text-slate-300 text-sm leading-relaxed">
                     "{r.riscos?.descricao || 'Nenhum risco crítico identificado para o período.'}"
                   </div>
                </div>
             </div>
          </div>

        </div>

        <div className="p-8 border-t border-slate-800 bg-slate-950 flex justify-between items-center text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">
           <span>Fonte Oficial: {post.fonteOficial}</span>
           <div className="flex gap-4">
                {post.lastEditor && <span className="text-emerald-400">{post.lastEditor}</span>}
                <span>SGC - Monitoramento de Resultados v1.3</span>
           </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  LineChart,
  Line,
  PieChart,
  Pie,
  Cell,
  ComposedChart
} from 'recharts';
import { ChartConfig, ExternalChartData } from '../types';

interface ChartRendererProps {
  config: ChartConfig;
}

const COLORS = ['#0ea5e9', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#6366f1'];

const formatValue = (value: number) => {
    return new Intl.NumberFormat('pt-BR', { maximumFractionDigits: 2 }).format(value);
};

export const ChartRenderer: React.FC<ChartRendererProps> = ({ config }) => {
  const { type, color: mainColor, barLabel, lineLabel, title } = config;

  const { processedData, dataKeys, isComplex, complexConfig } = useMemo(() => {
    try {
      // CASO 0: Formato Complexo
      if (config.data && !Array.isArray(config.data) && typeof config.data === 'object') {
        const extData = config.data as any; 

        if ('labels' in extData || 'series' in extData) {
          const labels = Array.isArray(extData.labels) ? extData.labels : [];
          const series = Array.isArray(extData.series) ? extData.series : [];

          const normalized = labels.map((label: string, index: number) => {
            const item: any = { label };
            series.forEach((s: any, sIndex: number) => {
              if (!s) return;
              const key = s.name || s.label || `series_${sIndex}`;
              const val = (Array.isArray(s.data) && s.data[index] !== undefined) ? s.data[index] : null;
              item[key] = val;
            });
            return item;
          });

          const keys = series
            .filter((s: any) => s)
            .map((s: any) => s.name || s.label || 'unknown');

          return {
            processedData: normalized,
            dataKeys: keys,
            isComplex: true,
            complexConfig: extData as ExternalChartData
          };
        }
      }

      // CASO 1: Formato "Nested Values"
      if (config.data && Array.isArray(config.data) && config.data.length > 0) {
        const firstItem = config.data[0];
        if (firstItem && 'values' in firstItem && Array.isArray(firstItem.values)) {
          const seriesList = config.data as any[];
          const uniqueLabels = new Set<string>();

          seriesList.forEach(series => {
            if (Array.isArray(series.values)) {
              series.values.forEach((v: any) => {
                const xAxisLabel = v.city || v.label;
                if (xAxisLabel) uniqueLabels.add(xAxisLabel);
              });
            }
          });

          const normalized = Array.from(uniqueLabels).map(xAxisLabel => {
            const row: any = { label: xAxisLabel };
            seriesList.forEach(series => {
              const seriesName = series.label || series.name || 'Unnamed';
              const point = series.values?.find((v: any) => (v.city || v.label) === xAxisLabel);
              if (point) {
                row[seriesName] = point.value;
              }
            });
            return row;
          });

          const keys = seriesList.map(s => s.label || s.name || 'Unknown');

          return { processedData: normalized, dataKeys: keys, isComplex: false };
        }
      }

      // CASO 2: Formato "Series" (Antigo)
      if (config.series && Array.isArray(config.series)) {
        const allLabels = new Set<string>();
        config.series.forEach(s => s.data.forEach(d => allLabels.add(d.label)));

        const normalized = Array.from(allLabels).map(label => {
          const item: any = { label };
          config.series?.forEach(s => {
            const point = s.data.find(d => d.label === label);
            if (point) {
              item[s.name] = point.value;
            }
          });
          return item;
        });

        return {
          processedData: normalized,
          dataKeys: config.series.map(s => s.name),
          isComplex: false
        };
      }

      // CASO 3: Formato "Flat" (Simples & Novo AdminPanel)
      if (config.data && Array.isArray(config.data) && config.data.length > 0) {
        const first = config.data[0];
        if (!('values' in first) && !('series' in first)) {
          // Detecta se tem chaves especiais (barValue/lineValue)
          if (first.barValue !== undefined || first.lineValue !== undefined) {
               return { processedData: config.data, dataKeys: ['barValue', 'lineValue'], isComplex: false };
          }

          const keys = Object.keys(first).filter(k => k !== 'label' && k !== 'city' && k !== 'color');
          const normalized = config.data.map((item: any) => ({
            ...item,
            label: item.label || item.city || 'Unknown'
          }));

          return { processedData: normalized, dataKeys: keys, isComplex: false };
        }
      }

      return { processedData: [], dataKeys: [], isComplex: false };

    } catch (e) {
      console.error("Erro ao processar dados do gráfico:", e);
      return { processedData: [], dataKeys: [], isComplex: false };
    }
  }, [config]);

  const renderChart = () => {
    if (!processedData || processedData.length === 0) {
      return (
        <div className="flex items-center justify-center h-full text-slate-500 text-sm">
          Sem dados para exibir
        </div>
      );
    }

    // Margens ajustadas para evitar cortes
    const commonMargin = { top: 20, right: 30, bottom: 20, left: 50 };
    const domainWithPadding: [number, any] = [0, (dataMax: number) => Math.ceil(dataMax * 1.05)];

    // NOVO: Detecta se é o formato misto do novo AdminPanel (com barValue e lineValue)
    if (processedData.length > 0 && (processedData[0].barValue !== undefined || processedData[0].lineValue !== undefined)) {
        // Verifica se realmente existe dado de linha para desenhar
        const hasLineData = processedData.some((d: any) => d.lineValue !== undefined && d.lineValue !== null);

        // -- RENDERIZAÇÃO ESPECÍFICA BASEADA NO TIPO --

        // 1. PIZZA
        if (type === 'pie') {
             return (
              <PieChart>
                 <Pie
                  data={processedData}
                  cx="50%"
                  cy="50%"
                  labelLine={false}
                  label={({ cx, cy, midAngle, innerRadius, outerRadius, percent }) => {
                    const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
                    const x = cx + radius * Math.cos(-midAngle * Math.PI / 180);
                    const y = cy + radius * Math.sin(-midAngle * Math.PI / 180);
                    return percent > 0.05 ? (
                      <text x={x} y={y} fill="white" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" fontSize={12}>
                        {`${(percent * 100).toFixed(0)}%`}
                      </text>
                    ) : null;
                  }}
                  outerRadius={80}
                  dataKey="barValue" // Usa o valor principal
                  nameKey="label"
                >
                  {processedData.map((entry: any, index: number) => (
                    <Cell key={`cell-${index}`} fill={entry.color || COLORS[index % COLORS.length]} stroke="rgba(0,0,0,0.2)" />
                  ))}
                </Pie>
                <Tooltip formatter={(value: number) => [formatValue(value), '']} contentStyle={{ backgroundColor: '#1e293b', borderRadius: '8px', border: '1px solid #334155', color: '#f8fafc' }} />
                <Legend />
              </PieChart>
            );
        }

        // 2. LINHA (Se selecionado Linha, transformamos o barValue em Linha Principal)
        if (type === 'line') {
             return (
                <ComposedChart 
                    data={processedData} 
                    margin={commonMargin}
                >
                  <CartesianGrid stroke="#334155" strokeDasharray="3 3" vertical={false} />
                  <XAxis dataKey="label" scale="point" padding={{ left: 60, right: 60 }} stroke="#94a3b8" fontSize={11} tickLine={false} />
                  <YAxis stroke="#94a3b8" fontSize={11} tickLine={false} domain={domainWithPadding} tickFormatter={formatValue} tickCount={5} interval={0} />
                  <Tooltip formatter={(value: number) => [formatValue(value), '']} contentStyle={{ backgroundColor: '#1e293b', borderRadius: '8px', border: '1px solid #334155', color: '#f8fafc' }} />
                  <Legend wrapperStyle={{ paddingTop: '10px' }} />

                  {/* Renderiza o valor principal como Linha ao invés de Barra */}
                  <Line 
                    type="monotone"
                    dataKey="barValue" 
                    name={barLabel || "Valor"} 
                    stroke={mainColor || '#10b981'} 
                    strokeWidth={3} 
                    dot={{ r: 4 }} 
                    activeDot={{ r: 6 }}
                  />

                  {/* Se houver linha secundária (Meta), renderiza também */}
                  {hasLineData && (
                    <Line type="monotone" dataKey="lineValue" name={lineLabel || "Meta"} stroke="#f59e0b" strokeWidth={3} dot={{ r: 4 }} activeDot={{ r: 6 }} strokeDasharray="5 5" />
                  )}
                </ComposedChart>
            );
        }

        // 3. BARRA (Default - ComposedChart Misto)
        return (
            <ComposedChart 
                data={processedData} 
                margin={commonMargin}
                barCategoryGap="60%"
                barGap={0}
            >
              <CartesianGrid stroke="#334155" strokeDasharray="3 3" vertical={false} />
              <XAxis 
                dataKey="label" 
                scale="point" 
                padding={{ left: 60, right: 60 }} 
                stroke="#94a3b8" 
                fontSize={11} 
                tickLine={false} 
              />
              <YAxis 
                stroke="#94a3b8" 
                fontSize={11} 
                tickLine={false} 
                domain={domainWithPadding} 
                tickFormatter={formatValue}
                tickCount={5}
                interval={0}
              />
              <Tooltip formatter={(value: number) => [formatValue(value), '']} contentStyle={{ backgroundColor: '#1e293b', borderRadius: '8px', border: '1px solid #334155', color: '#f8fafc' }} />
              <Legend wrapperStyle={{ paddingTop: '10px' }} />

              <Bar 
                dataKey="barValue" 
                name={barLabel || "Valor"} 
                radius={[6, 6, 0, 0]} 
                maxBarSize={90}
              >
                 {processedData.map((entry: any, i: number) => (
                  <Cell key={`cell-${i}`} fill={entry.color || '#10b981'} />
                ))}
              </Bar>
              {hasLineData && (
                <Line type="monotone" dataKey="lineValue" name={lineLabel || "Meta"} stroke="#f59e0b" strokeWidth={3} dot={{ r: 4 }} activeDot={{ r: 6 }} />
              )}
            </ComposedChart>
        );
    }

    if (isComplex && complexConfig && complexConfig.series) {
      return (
        <ComposedChart 
            data={processedData} 
            margin={commonMargin}
            barCategoryGap="45%"
            barGap={0}
        >
          <CartesianGrid stroke="#334155" strokeDasharray="3 3" vertical={false} />
          <XAxis dataKey="label" scale="point" padding={{ left: 10, right: 10 }} stroke="#94a3b8" fontSize={11} tickLine={false} />
          <YAxis yAxisId="left" orientation="left" stroke="#94a3b8" fontSize={11} tickLine={false} domain={domainWithPadding} label={complexConfig.yAxes?.left?.title ? { value: complexConfig.yAxes.left.title, angle: -90, position: 'insideLeft', fill: '#94a3b8', fontSize: 10 } : undefined} />
          <YAxis yAxisId="right" orientation="right" stroke="#94a3b8" fontSize={11} tickLine={false} hide={!complexConfig.yAxes?.right} domain={domainWithPadding} label={complexConfig.yAxes?.right?.title ? { value: complexConfig.yAxes.right.title, angle: 90, position: 'insideRight', fill: '#94a3b8', fontSize: 10 } : undefined} />
          <Tooltip formatter={(value: number) => [formatValue(value), '']} contentStyle={{ backgroundColor: '#1e293b', borderRadius: '8px', border: '1px solid #334155', color: '#f8fafc' }} />
          <Legend wrapperStyle={{ paddingTop: '10px' }} />
          {complexConfig.series.map((serie, index) => {
            if (!serie) return null; 
            const serieColor = serie.color || COLORS[index % COLORS.length];
            const yAxisId = serie.yAxis === 'right' ? 'right' : 'left';
            const dataKey = serie.name || serie.label || `series_${index}`;
            if (serie.type === 'line') {
              return <Line key={dataKey} type="monotone" dataKey={dataKey} name={dataKey} stroke={serieColor} strokeWidth={3} yAxisId={yAxisId} dot={{ r: 4 }} activeDot={{ r: 6 }} />;
            } else {
              return <Bar key={dataKey} dataKey={dataKey} name={dataKey} fill={serieColor} yAxisId={yAxisId} radius={[4, 4, 0, 0]} maxBarSize={60} />;
            }
          })}
        </ComposedChart>
      );
    }

    switch (type) {
      case 'line':
        return (
          <LineChart data={processedData} margin={commonMargin}>
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
            <XAxis dataKey="label" stroke="#94a3b8" fontSize={12} tickLine={false} />
            <YAxis stroke="#94a3b8" fontSize={12} tickLine={false} domain={domainWithPadding} tickFormatter={formatValue} />
            <Tooltip formatter={(value: number) => [formatValue(value), '']} contentStyle={{ backgroundColor: '#1e293b', borderRadius: '8px', border: '1px solid #334155', color: '#f8fafc' }} itemStyle={{ color: '#e2e8f0' }} />
            <Legend wrapperStyle={{ paddingTop: '10px' }} />
            {dataKeys.map((key, index) => (
              <Line key={key} type="monotone" dataKey={key} name={key === 'value' ? 'Valor' : key} stroke={COLORS[index % COLORS.length]} strokeWidth={3} activeDot={{ r: 6 }} />
            ))}
          </LineChart>
        );
      case 'pie':
        const pieDataKey = dataKeys[0] || 'value';
        return (
          <PieChart>
             <Pie
              data={processedData}
              cx="50%"
              cy="50%"
              labelLine={false}
              label={({ cx, cy, midAngle, innerRadius, outerRadius, percent }) => {
                const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
                const x = cx + radius * Math.cos(-midAngle * Math.PI / 180);
                const y = cy + radius * Math.sin(-midAngle * Math.PI / 180);
                return percent > 0.05 ? (
                  <text x={x} y={y} fill="white" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" fontSize={12}>
                    {`${(percent * 100).toFixed(0)}%`}
                  </text>
                ) : null;
              }}
              outerRadius={80}
              dataKey={pieDataKey}
              nameKey="label"
            >
              {processedData.map((entry: any, index: number) => (
                <Cell key={`cell-${index}`} fill={entry.color || COLORS[index % COLORS.length]} stroke="rgba(0,0,0,0.2)" />
              ))}
            </Pie>
            <Tooltip formatter={(value: number) => [formatValue(value), '']} contentStyle={{ backgroundColor: '#1e293b', borderRadius: '8px', border: '1px solid #334155', color: '#f8fafc' }} />
            <Legend />
          </PieChart>
        );
      case 'bar':
      default:
        return (
          <BarChart 
            data={processedData} 
            margin={commonMargin}
            barCategoryGap="60%"
            barGap={0}
          >
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#334155" />
            <XAxis dataKey="label" stroke="#94a3b8" fontSize={12} tickLine={false} />
            <YAxis 
                stroke="#94a3b8" 
                fontSize={12} 
                tickLine={false} 
                domain={domainWithPadding} 
                tickFormatter={formatValue} 
                tickCount={5}
                interval={0}
            />
            <Tooltip formatter={(value: number) => [formatValue(value), '']} cursor={{ fill: '#334155', opacity: 0.4 }} contentStyle={{ backgroundColor: '#1e293b', borderRadius: '8px', border: '1px solid #334155', color: '#f8fafc' }} itemStyle={{ color: '#e2e8f0' }} />
            <Legend wrapperStyle={{ paddingTop: '10px' }} />
            {dataKeys.map((key, index) => (
              <Bar 
                key={key} 
                dataKey={key} 
                name={key === 'value' ? 'Quantidade' : key} 
                fill={dataKeys.length === 1 && mainColor ? mainColor : COLORS[index % COLORS.length]} 
                radius={[6, 6, 0, 0]}
                maxBarSize={90}
               >
                {processedData.map((entry: any, i: number) => (
                  <Cell key={`cell-${i}`} fill={entry.color || (dataKeys.length === 1 && mainColor ? mainColor : COLORS[index % COLORS.length])} />
                ))}
              </Bar>
            ))}
          </BarChart>
        );
    }
  };

  return (
    <div className="w-full h-full min-h-[300px] flex flex-col relative">
      {/* Título interno exibido de foroma fixa e estilizada como legenda */}
      {title && (
          <div className="w-full text-center pb-2 z-10">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest bg-[#0B1120]/50 px-3 py-1 rounded-full border border-slate-800">
                  {title}
              </span>
          </div>
      )}
      <div className="flex-1 min-h-0">
        <ResponsiveContainer width="100%" height="100%">
            {renderChart()}
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export enum TopicId {
  SAUDE = 'saude',
  EDUCACAO = 'educacao',
  DESENVOLVIMENTO_SOCIAL = 'social',
  FINANCAS = 'financas',
  ESPORTE_CULTURA_LAZER = 'esporte',
  AGRICULTURA = 'agricultura',
  INFRAESTRUTURA = 'infraestrutura',
  PLANEJAMENTO = 'planejamento',
}

export interface ProgressUpdate {
  date: number;
  percentage: number;
  whatWasDone: string;
  whatIsMissing: string;
}

export interface SemaforoConfig {
  green: string;
  yellow: string;
  red: string;
}

export interface ReportSection {
  // 1. Identificação & Estratégia
  objetivo: string;
  importanciaPrefeito: string;
  formula: string;
  acaoCrise: string; // Ação automática se RED

  secretaria: string;
  periodo: string;
  responsavelPolitico: string;
  responsavelTecnico: string;
  pontoFocal: {
    nome: string;
    cargo: string;
    telefone: string;
    email: string;
  };

  // 2. Resumo Executivo
  resumoAvanços: string;
  resumoAtrasos: string;
  resumoDecisoes: string;

  // 3. Dados do Gráfico (Gerenciado via ChartConfig, mas referenciado aqui logicamente)

  // 5. Informações do Indicador (Antigo Indicadores Secundários)
  // Campos personalizáveis do cabeçalho da tabela
  headerIndicador?: string;
  headerResultado?: string;
  headerMeta?: string;
  headerExtra?: string; // Novo cabeçalho opcional
  showExtraColumn?: boolean; // Controle de visibilidade da coluna extra

  // Campos: Resultado atual, Meta (trimestre/ano), Extra, Sinal (🟢/🟡/🔴), Tendência (↑/→/↓) e Fonte do dado
  indicadoresChave: Array<{
    nome: string; // Nome do indicador/Variável
    resultado: string;
    meta: string;
    extra?: string; // Nova coluna extra
    status: 'green' | 'yellow' | 'red'; // Sinal
    tendencia: 'up' | 'stable' | 'down';
    fonte: string;
  }>;

  // 6. Metas Prioritárias
  metasPrioritarias: Array<{
    meta: string;
    prazo: string;
    responsavel: string;
    status: 'green' | 'yellow' | 'red';
    evidencia: string; // Link/Foto/SEI
    obs: string; // Observação objetiva
  }>;

  // 7. Problemas Críticos
  problemasCriticos: Array<{
    problema: string;
    impacto: 'Alto' | 'Médio' | 'Baixo';
    causa: string;
    acao: string;
    prazo: string;
  }>;

  // 6. Decisões Prefeito (Mantido no index 7 logicamente ou grupo de problemas)
  decisoesPrefeito: Array<{
    tema: string;
    decisao: string;
    consequencia: string;
    prazo: string;
  }>;

  // 8. Riscos e Alertas
  riscos: {
    tipos: string[];
    descricao: string;
  };

  // 9. Compromissos Próximo Período
  compromissos: Array<{
    compromisso: string;
    prazo: string;
    responsavel: string;
    evidencia: string;
  }>;

  // 10. Configuração de Layout (Novo)
  layout?: {
    chartWidthPercent: number; // Porcentagem de largura do gráfico (ex: 40)
    isVertical: boolean; // Se verdadeiro, empilha gráfico e tabela
    order: 'chart-first' | 'table-first'; // Quem aparece primeiro/esquerda
  };

  // 11. Anexos
  anexos: string;
}

export interface ExternalChartData {
  labels: string[];
  series: Array<{
    name?: string;
    label?: string;
    data: any[];
    type?: 'bar' | 'line';
    color?: string;
    yAxis?: 'left' | 'right';
  }>;
  yAxes?: {
    left?: { title?: string };
    right?: { title?: string };
  };
}

export interface ChartConfig {
  type: 'bar' | 'line' | 'pie';
  title: string;
  barLabel?: string; // Nome da série de barras (ex: Realizado)
  lineLabel?: string; // Nome da série de linha (ex: Meta)
  data?: any; // Array de objetos { label, value, color }
  // Nova estrutura para Múltiplas Linhas
  multiLineSeries?: Array<{
    label: string;
    color: string;
    data: Array<{ x: string; y: number }>;
  }>;
  series?: any[];
  color?: string; // Cor padrão
  options?: any;
}

export interface Post {
  id: string;
  topicId: TopicId;
  indicatorName?: string; // Nome principal do Indicador (Cabeçalho)
  description: string;
  chartConfig: ChartConfig;
  createdAt: number;
  order?: number; // Campo para ordenação personalizada

  responsavel: string;
  fonteOficial: string;
  recorrencia: string;
  dataAtualizacao: number;
  lastEditor?: string; // Novo campo para rastrear quem editou

  semaforoRules: SemaforoConfig;
  semaforoGeral: 'green' | 'yellow' | 'red'; // Novo campo para o card da lista

  progress: number;
  progressHistory: ProgressUpdate[];
  report: ReportSection;
}

export interface TopicDef {
  id: TopicId;
  label: string;
  iconName: string;
  color: string;
  description: string;
}

import React, { useState, useRef } from 'react';
import { X, Trash2, Plus, Lock, TrendingUp, TrendingDown, Minus, History, ShieldAlert, Target, AlertTriangle, Calendar, FileText, Info, ListChecks, Clock, CheckCircle2, AlertCircle, ClipboardList, Pencil, BookOpen, AlertOctagon, GraduationCap, Link as LinkIcon, PieChart, BarChart, LineChart, GripVertical, Filter, ToggleLeft, ToggleRight, Code, Upload, FileSpreadsheet, LayoutTemplate, ArrowLeftRight, ArrowUpDown, Columns, Layers } from 'lucide-react';
import { ChartConfig, Post, TopicId, SemaforoConfig, ProgressUpdate, ReportSection } from '../types';
import { TOPICS } from '../constants';
import { read, utils } from 'xlsx';

interface AdminPanelProps {
  isOpen: boolean;
  onClose: () => void;
  posts: Post[];
  onAddPost: (topicId: TopicId, description: string, chartConfig: ChartConfig, extra: any) => Promise<boolean | void>;
  onEditPost: (postId: string, topicId: TopicId, description: string, chartConfig: ChartConfig, extra: any) => Promise<boolean | void>;
  onDeletePost: (postId: string) => void;
  usingServer: boolean;
}

const INITIAL_REPORT: ReportSection = {
  // Novos campos estratégicos
  objetivo: '', importanciaPrefeito: '', formula: '', acaoCrise: '',
  responsavelTecnico: '', 

  secretaria: '', periodo: '', responsavelPolitico: '', 
  pontoFocal: { nome: '', cargo: '', telefone: '', email: '' },
  resumoAvanços: '', resumoAtrasos: '', resumoDecisoes: '',

  // Cabeçalhos personalizáveis (com defaults)
  headerIndicador: 'Indicador',
  headerResultado: 'Resultado',
  headerMeta: 'Meta',
  headerExtra: 'Variação', 
  showExtraColumn: false, // Default: oculta

  indicadoresChave: [], metasPrioritarias: [], problemasCriticos: [], decisoesPrefeito: [],
  riscos: { tipos: [], descricao: '' }, compromissos: [], anexos: '',

  // Layout Default
  layout: {
      chartWidthPercent: 40,
      isVertical: false,
      order: 'chart-first'
  }
};

const INITIAL_SEMAFORO: SemaforoConfig = {
  green: 'Matrículas consolidadas e validadas no sistema',
  yellow: 'Pendências de validação / risco de inconsistência',
  red: 'Matrículas não lançadas ou rejeitadas pelo sistema'
};

const USERS_MAP: Record<string, string> = {
  'azul': 'Lucas Araujo dos Santos',
  'amarelo': 'Gilda Natali Mendes dos Santos Lemos',
  'preto': 'Ana Paula Daltro Oliveira',
  'rosa': 'Maiara dos Santos Maia'
};

// --- Helpers de Formatação ---
const formatCurrency = (value: number) => {
  return value.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
};

const handleCurrencyInput = (value: string): number => {
  // Remove tudo que não é dígito
  const digits = value.replace(/\D/g, '');
  // Divide por 100 para considerar os centavos
  return (parseInt(digits) || 0) / 100;
};
// -----------------------------

// Interface auxiliar para o State de Múltiplas Linhas
interface LineSeriesState {
  id: string; // Para manipulação interna
  label: string;
  color: string;
  data: Array<{ x: string; y: number }>;
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ 
  isOpen, onClose, posts, onAddPost, onEditPost, onDeletePost
}) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState('');
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState('');
  const [activeTab, setActiveTab] = useState<'add' | 'list'>('add');
  const [formStep, setFormStep] = useState<number>(1);
  const [editingPostId, setEditingPostId] = useState<string | null>(null);

  // Filter State
  const [filterTopic, setFilterTopic] = useState<string>('all');

  // Drag and Drop State
  const dragItem = useRef<number | null>(null);
  const dragOverItem = useRef<number | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  // Form State
  const [indicatorName, setIndicatorName] = useState(''); // Nome do Indicador (Cabeçalho)
  const [chartTitle, setChartTitle] = useState(''); // Título do Gráfico (Interno)
  const [description, setDescription] = useState('');
  const [selectedTopic, setSelectedTopic] = useState<TopicId>(TopicId.EDUCACAO);
  const [responsavel, setResponsavel] = useState('');
  const [fonteOficial, setFonteOficial] = useState('');
  const [recorrencia, setRecorrencia] = useState('Mensal');

  // Novo State: Semáforo Geral e Tipo de Gráfico
  const [semaforoGeral, setSemaforoGeral] = useState<'green'|'yellow'|'red'>('green');
  const [chartType, setChartType] = useState<'bar'|'line'|'pie'>('bar');

  // Labels Customizados para o Gráfico (BARRAS)
  const [barLabel, setBarLabel] = useState('Realizado');
  const [lineLabel, setLineLabel] = useState('Meta');

  // Controle de exibição da coluna de Linha (BARRAS)
  const [showLineData, setShowLineData] = useState(false);

  // JSON Mode State (Passo 3)
  const [isJsonMode, setIsJsonMode] = useState(false);
  const [jsonInput, setJsonInput] = useState('');

  // File Upload Ref (Passo 5)
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [semaforoRules, setSemaforoRules] = useState<SemaforoConfig>(INITIAL_SEMAFORO);
  const [report, setReport] = useState<ReportSection>(INITIAL_REPORT);
  const [progress, setProgress] = useState(0);
  const [progressHistory, setProgressHistory] = useState<ProgressUpdate[]>([]);

  // Builder rows (BARRAS): Agora suporta barValue e lineValue
  const [builderRows, setBuilderRows] = useState<any[]>([{ label: 'Mês 1', barValue: 0, lineValue: 0, color: '#10b981' }]);

  // Builder Series (LINHAS): State para múltiplas séries
  const [lineSeries, setLineSeries] = useState<LineSeriesState[]>([
    { 
      id: '1', 
      label: 'Série 1', 
      color: '#10b981', 
      data: [{ x: 'Jan', y: 0 }, { x: 'Fev', y: 0 }] 
    }
  ]);

  // Risco Personalizado
  const [customRiskInput, setCustomRiskInput] = useState('');
  const [isAddingCustomRisk, setIsAddingCustomRisk] = useState(false);

  // State para Nova Movimentação (Step 9)
  const [newMoveDate, setNewMoveDate] = useState(new Date().toISOString().split('T')[0]);
  const [newMovePct, setNewMovePct] = useState<number | ''>('');
  const [newMoveDone, setNewMoveDone] = useState('');
  const [newMoveMissing, setNewMoveMissing] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setLoginError('');
    const normalizedPass = passwordInput.trim().toLowerCase();

    if (USERS_MAP[normalizedPass]) {
      setIsAuthenticated(true);
      setCurrentUser(USERS_MAP[normalizedPass]);
    } else {
      setLoginError('Senha incorreta.');
      if (navigator.vibrate) navigator.vibrate(200);
    }
  };

  const handleEditClick = (post: Post) => {
    setEditingPostId(post.id);
    setSelectedTopic(post.topicId);

    // Separando Nome do Indicador do Título do Gráfico
    setIndicatorName(post.indicatorName || post.chartConfig.title);
    setChartTitle(post.chartConfig.title);

    setDescription(post.description);
    setResponsavel(post.responsavel || '');
    setFonteOficial(post.fonteOficial || '');
    setRecorrencia(post.recorrencia || 'Mensal');
    setSemaforoRules(post.semaforoRules || INITIAL_SEMAFORO);
    setSemaforoGeral(post.semaforoGeral || 'green');
    setChartType(post.chartConfig.type || 'bar');

    // Carrega Labels customizados
    setBarLabel(post.chartConfig.barLabel || 'Realizado');
    setLineLabel(post.chartConfig.lineLabel || 'Meta');

    // Lógica para determinar se a coluna extra deve ser mostrada em posts antigos
    const shouldShowExtra = post.report.showExtraColumn !== undefined 
        ? post.report.showExtraColumn 
        : (!!post.report.headerExtra || post.report.indicadoresChave.some((i: any) => i.extra));

    setReport({ 
        ...INITIAL_REPORT, 
        ...post.report,
        showExtraColumn: shouldShowExtra,
        layout: post.report.layout || INITIAL_REPORT.layout
    });
    setProgress(post.progress || 0);
    setProgressHistory(post.progressHistory || []);

    // Inicializa JSON Mode se necessário
    setJsonInput(JSON.stringify(post.chartConfig, null, 2));

    // Lógica de Carregamento de Dados (Barras vs Linhas)
    if (post.chartConfig.multiLineSeries) {
        // Carrega séries de linhas
        const loadedSeries = post.chartConfig.multiLineSeries.map((s, idx) => ({
            id: String(idx),
            label: s.label,
            color: s.color,
            data: s.data
        }));
        setLineSeries(loadedSeries);
        // Limpa builder de barras para evitar confusão, embora não seja estritamente necessário
        setBuilderRows([]); 
    } else if (Array.isArray(post.chartConfig.data)) {
        // Carrega builder de barras/pizza (Legacy ou Padrão)
        const hasLine = post.chartConfig.data.some((d: any) => d.lineValue !== undefined && d.lineValue !== null && d.lineValue !== '');
        setShowLineData(hasLine);

        const loadedData = post.chartConfig.data.map((d: any) => ({
            label: d.label,
            color: d.color || '#10b981',
            barValue: d.barValue !== undefined ? d.barValue : (d.Valor !== undefined ? d.Valor : 0),
            lineValue: d.lineValue || 0
        }));
        setBuilderRows(loadedData);
        // Reseta linhas para default
        setLineSeries([{ id: '1', label: 'Série 1', color: '#10b981', data: [{ x: 'Jan', y: 0 }] }]);
    } else {
        setBuilderRows([]);
        setShowLineData(false);
    }

    setActiveTab('add');
    setFormStep(1);
    setIsJsonMode(false); 
  };

  const handleSubmit = async () => {
    let config: ChartConfig;

    if (isJsonMode) {
        try {
            config = JSON.parse(jsonInput);
        } catch (e) {
            alert('Erro no JSON do Gráfico. Verifique a sintaxe.');
            return;
        }
    } else {
        // Constrói o Config baseado no Tipo selecionado
        if (chartType === 'line') {
             // Modo Múltiplas Linhas
             const cleanedSeries = lineSeries.map(s => ({
                 label: s.label,
                 color: s.color,
                 data: s.data
             }));

             config = {
                 type: 'line',
                 title: chartTitle,
                 multiLineSeries: cleanedSeries,
                 data: [] // Deixa vazio para não confundir o renderer legado
             };
        } else {
            // Modo Barras/Pizza
            const cleanData = builderRows.map(row => {
                const { lineValue, ...rest } = row;
                if (showLineData) {
                    return row;
                }
                return rest; 
            });

            config = { 
                type: chartType, 
                title: chartTitle, 
                barLabel,  
                lineLabel: showLineData ? lineLabel : undefined, 
                data: cleanData 
            };
        }
    }

    const finalReport = {
      ...report,
      responsavelPolitico: responsavel,
    };

    const extra = { 
        indicatorName, 
        responsavel, 
        fonteOficial, 
        recorrencia, 
        dataAtualizacao: Date.now(), 
        semaforoRules, 
        semaforoGeral, 
        progress, 
        progressHistory, 
        report: finalReport,
        lastEditor: currentUser 
    };

    let success;
    if (editingPostId) success = await onEditPost(editingPostId, selectedTopic, description, config, extra);
    else success = await onAddPost(selectedTopic, description, config, extra);

    if (success !== false) {
      setEditingPostId(null); 
      setIndicatorName('');
      setChartTitle('');
      setReport(INITIAL_REPORT); 
      setActiveTab('list');
      setBuilderRows([{ label: 'Mês 1', barValue: 0, lineValue: 0, color: '#10b981' }]); 
      setLineSeries([{ id: '1', label: 'Série 1', color: '#10b981', data: [{ x: 'Jan', y: 0 }] }]);
      setBarLabel('Realizado');
      setLineLabel('Meta');
      setShowLineData(false);
      setIsJsonMode(false);
      setJsonInput('');
      setProgress(0); setProgressHistory([]);
    }
  };

  // ... (funções auxiliares addProgressMove, addCustomRisk, handleFileUpload, etc. mantidas iguais) ...
  const addProgressMove = () => {
    if (newMovePct === '') return;
    const dateObj = new Date(newMoveDate);
    const utcDate = new Date(dateObj.valueOf() + dateObj.getTimezoneOffset() * 60000).getTime();

    const update: ProgressUpdate = {
      date: utcDate,
      percentage: Number(newMovePct),
      whatWasDone: newMoveDone,
      whatIsMissing: newMoveMissing
    };
    setProgress(Number(newMovePct));
    setProgressHistory([update, ...progressHistory]);
    setNewMovePct('');
    setNewMoveDone('');
    setNewMoveMissing('');
  };

  const addCustomRisk = () => {
    if (customRiskInput.trim()) {
        const newTypes = [...report.riscos.tipos, customRiskInput.trim()];
        setReport({...report, riscos: {...report.riscos, tipos: newTypes}});
        setCustomRiskInput('');
        setIsAddingCustomRisk(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();

      reader.onload = (evt) => {
        const bstr = evt.target?.result;
        const wb = read(bstr, { type: 'binary' });
        const wsname = wb.SheetNames[0];
        const ws = wb.Sheets[wsname];
        const data = utils.sheet_to_json(ws, { header: 1 }); 

        const statusMap: Record<string, 'green' | 'yellow' | 'red'> = {
            'v': 'green', 'verde': 'green',
            'a': 'yellow', 'amarelo': 'yellow',
            'red': 'red', 'vermelho': 'red', 'r': 'red'
        };

        const trendMap: Record<string, 'up' | 'stable' | 'down'> = {
            'c': 'up', 'crescimento': 'up',
            'e': 'stable', 'estavel': 'stable', 'estável': 'stable',
            'q': 'down', 'queda': 'down'
        };

        let foundExtraColumn = false;

        const rows = data.slice(1).map((row: any) => {
             const extraVal = row[3] || '';
             if (extraVal) foundExtraColumn = true;
             return {
                 nome: row[0] || '',
                 resultado: row[1] || '',
                 meta: row[2] || '',
                 extra: extraVal, 
                 status: statusMap[String(row[4]).toLowerCase()] || 'green',
                 tendencia: trendMap[String(row[5]).toLowerCase()] || 'stable',
                 fonte: row[6] || ''
             };
        }).filter(r => r.nome); 

        if (rows.length > 0) {
            setReport(prev => ({
                ...prev,
                showExtraColumn: foundExtraColumn || prev.showExtraColumn, 
                indicadoresChave: [...prev.indicadoresChave, ...rows]
            }));
            alert(`${rows.length} indicadores importados com sucesso! ${foundExtraColumn ? '(Coluna Extra identificada e ativada)' : ''}`);
        } else {
            alert('Nenhum dado válido encontrado na planilha.');
        }
      };

      reader.readAsBinaryString(file);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const filteredPosts = posts.filter(p => filterTopic === 'all' || p.topicId === filterTopic);

  // Helpers para Múltiplas Linhas
  const addLineSeries = () => {
      setLineSeries([...lineSeries, {
          id: Date.now().toString(),
          label: `Série ${lineSeries.length + 1}`,
          color: '#3b82f6',
          data: [{ x: 'Jan', y: 0 }]
      }]);
  };

  const removeLineSeries = (index: number) => {
      if (lineSeries.length > 1) {
          setLineSeries(lineSeries.filter((_, i) => i !== index));
      }
  };

  const addPointToSeries = (seriesIndex: number) => {
      const newSeries = [...lineSeries];
      newSeries[seriesIndex].data.push({ x: 'Novo', y: 0 });
      setLineSeries(newSeries);
  };

  const removePointFromSeries = (seriesIndex: number, pointIndex: number) => {
      const newSeries = [...lineSeries];
      if (newSeries[seriesIndex].data.length > 1) {
          newSeries[seriesIndex].data = newSeries[seriesIndex].data.filter((_, i) => i !== pointIndex);
          setLineSeries(newSeries);
      }
  };

  const updateSeriesField = (index: number, field: keyof LineSeriesState, value: any) => {
      const newSeries = [...lineSeries];
      (newSeries[index] as any)[field] = value;
      setLineSeries(newSeries);
  };

  const updateSeriesPoint = (seriesIndex: number, pointIndex: number, field: 'x' | 'y', value: any) => {
      const newSeries = [...lineSeries];
      newSeries[seriesIndex].data[pointIndex][field] = value;
      setLineSeries(newSeries);
  };

  // Drag and Drop Logic (mantida igual)
  const handleSort = async () => {
    if (dragItem.current === null || dragOverItem.current === null) return;
    const draggedIdx = dragItem.current;
    const overIdx = dragOverItem.current;
    if (draggedIdx === overIdx) return;
    dragItem.current = null;
    dragOverItem.current = null;
    setIsDragging(false);
    let updates: Post[] = [];
    if (filterTopic === 'all') {
        const _posts = [...posts];
        const draggedContent = _posts.splice(draggedIdx, 1)[0];
        _posts.splice(overIdx, 0, draggedContent);
        for (let i = 0; i < _posts.length; i++) {
            if (_posts[i].order !== i) updates.push({ ..._posts[i], order: i, lastEditor: currentUser });
        }
    } else {
        const currentVisible = [...filteredPosts];
        const availableSlots = currentVisible.map(p => p.order !== undefined ? p.order : 0);
        const draggedContent = currentVisible.splice(draggedIdx, 1)[0];
        currentVisible.splice(overIdx, 0, draggedContent);
        for (let i = 0; i < currentVisible.length; i++) {
            const p = currentVisible[i];
            const targetOrder = availableSlots[i];
            if (p.order !== targetOrder) updates.push({ ...p, order: targetOrder, lastEditor: currentUser });
        }
    }
    for (const updatedPost of updates) {
        await onEditPost(updatedPost.id, updatedPost.topicId, updatedPost.description, updatedPost.chartConfig, {
            ...updatedPost,
            report: updatedPost.report,
            progress: updatedPost.progress,
            progressHistory: updatedPost.progressHistory,
            lastEditor: updatedPost.lastEditor,
            order: updatedPost.order
        });
    }
  };

  if (!isAuthenticated) {
     // ... (Tela de Login mantida)
     return (
      <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-4">
        <div className="bg-slate-900 border border-slate-700 rounded-3xl p-8 md:p-12 w-full max-w-sm text-center space-y-8 shadow-2xl">
          <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mx-auto border border-emerald-500/20"><Lock className="text-emerald-400" size={32}/></div>
          <h2 className="text-2xl font-black text-white uppercase tracking-tighter">Gestão Técnica</h2>
          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <input type="password" value={passwordInput} onChange={e => { setPasswordInput(e.target.value); setLoginError(''); }} placeholder="Senha" className={`w-full p-4 bg-slate-950 border ${loginError ? 'border-red-500' : 'border-slate-800'} rounded-2xl text-white text-center font-black outline-none focus:ring-2 focus:ring-emerald-500`} autoFocus />
              {loginError && <p className="text-red-400 text-xs font-bold mt-2">{loginError}</p>}
            </div>
            <button type="submit" className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase hover:bg-emerald-500 transition-all">Acessar</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4">
      <div className="bg-[#0f172a] border border-slate-800 rounded-[2rem] w-full max-w-6xl h-[95vh] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">

        <div className="p-6 border-b border-slate-800 bg-slate-900/50 flex justify-between items-center">
          <div className="flex items-center gap-8">
            <h2 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-2"><ClipboardList className="text-emerald-500" /> Sala de Lançamento</h2>
            <div className="flex flex-col">
                 <span className="text-[10px] text-slate-500 font-bold uppercase">Logado como:</span>
                 <span className="text-xs text-emerald-400 font-black uppercase">{currentUser}</span>
            </div>
            <div className="flex bg-slate-800/50 p-1.5 rounded-2xl">
              <button onClick={() => setActiveTab('add')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase transition-all ${activeTab === 'add' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white'}`}>{editingPostId ? 'Editar' : 'Novo'}</button>
              <button onClick={() => setActiveTab('list')} className={`px-6 py-2 rounded-xl text-xs font-black uppercase transition-all ${activeTab === 'list' ? 'bg-emerald-600 text-white' : 'text-slate-400 hover:text-white'}`}>Catálogo</button>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-full text-slate-500"><X size={24}/></button>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {activeTab === 'add' && (
            <div className="w-64 bg-slate-900/30 border-r border-slate-800 p-6 flex flex-col gap-2 overflow-y-auto hidden md:flex">
              {[
                { id: 1, label: '1. Definição', icon: BookOpen },
                { id: 2, label: '2. Semáforo', icon: AlertOctagon },
                { id: 3, label: '3. Dados & Gráfico', icon: TrendingUp },
                { id: 4, label: '4. Resumo Exec.', icon: FileText },
                { id: 5, label: '5. Informações', icon: ListChecks }, 
                { id: 6, label: '6. Metas Priorit.', icon: Target },
                { id: 7, label: '7. Prob. & Decisões', icon: AlertTriangle },
                { id: 8, label: '8. Riscos', icon: ShieldAlert },
                { id: 9, label: '9. Histórico', icon: History },
                { id: 10, label: '10. Layout', icon: LayoutTemplate },
              ].map(step => (
                <button key={step.id} onClick={() => setFormStep(step.id)} className={`flex items-center gap-3 p-3.5 rounded-xl text-[10px] font-black uppercase tracking-widest text-left transition-all ${formStep === step.id ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'text-slate-500 hover:text-slate-300'}`}>
                  <step.icon size={16} className={formStep === step.id ? 'text-emerald-400' : 'text-slate-600'} />
                  {step.label}
                </button>
              ))}
              <div className="mt-auto pt-6 border-t border-slate-800">
                <button onClick={handleSubmit} className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black uppercase rounded-2xl shadow-xl transition-all active:scale-95">Salvar</button>
              </div>
            </div>
          )}

          <div className="flex-1 overflow-y-auto p-4 md:p-10 custom-scrollbar">
            {activeTab === 'add' ? (
              <div className="max-w-4xl mx-auto space-y-10 animate-in fade-in duration-500">

                {/* Steps 1 e 2 mantidos implicitamente iguais, vamos direto ao Step 3 */}
                {formStep === 1 && (
                  // ... (Mantido igual ao original)
                  <div className="space-y-8">
                    <h3 className="text-2xl font-black text-white border-b border-slate-800 pb-4">1. Definição Estratégica</h3>
                    <div className="grid md:grid-cols-2 gap-6">
                       <div className="space-y-2">
