                                                <p className={`text-xs font-bold leading-relaxed ${
                                                    post.semaforoGeral === 'red' ? 'text-red-400' : 
                                                    post.semaforoGeral === 'yellow' ? 'text-amber-400' : 
                                                    'text-emerald-400'
                                                }`}>
                                                    {getStatusText(post.semaforoGeral || 'green', post.semaforoRules)}
