        <p className="text-slate-400 max-w-xl mx-auto">Acompanhamento transparente das metas e resultados da gestão municipal.</p>
      </div>
      {isLoading ? <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-10 w-10 border-b-2 border-emerald-500"></div></div> : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          {TOPICS.map(topic => <TopicCard key={topic.id} topic={topic} onClick={(id) => navigate(`/topic/${id}`)} />)}
        </div>
      )}
    </div>
  );
};

const TopicDetailView = ({ posts, isLoading }: { posts: Post[], isLoading: boolean }) => {
  const { topicId } = useParams();
  const [selectedPost, setSelectedPost] = useState<Post | null>(null);

  // Estados para filtros e busca
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState('all');
  const [filterRecorrencia, setFilterRecorrencia] = useState('all');
  const [sortBy, setSortBy] = useState<'default' | 'alpha' | 'status'>('default');

  const topic = TOPICS.find(t => t.id === topicId);
  const topicPosts = posts.filter(p => p.topicId === topicId);

  // Extrair periodicidades únicas para este tópico
  const uniqueRecorrencias = useMemo(() => {
      const recs = new Set(topicPosts.map(p => p.recorrencia).filter(Boolean));
      return Array.from(recs).sort();
  }, [topicPosts]);

  // Lógica de Filtragem e Ordenação
  const processedPosts = useMemo(() => {
      let result = topicPosts.filter(post => {
          const matchesSearch = (post.indicatorName || post.chartConfig.title).toLowerCase().includes(searchTerm.toLowerCase());
          const matchesStatus = filterStatus === 'all' || (post.semaforoGeral || 'green') === filterStatus;
          const matchesRecorrencia = filterRecorrencia === 'all' || post.recorrencia === filterRecorrencia;
          return matchesSearch && matchesStatus && matchesRecorrencia;
      });

      if (sortBy === 'alpha') {
          result.sort((a, b) => (a.indicatorName || a.chartConfig.title).localeCompare(b.indicatorName || b.chartConfig.title));
      } else if (sortBy === 'status') {
          const weight = { red: 3, yellow: 2, green: 1 };
          result.sort((a, b) => {
              const wa = weight[a.semaforoGeral || 'green'] || 0;
              const wb = weight[b.semaforoGeral || 'green'] || 0;
              return wb - wa; // Críticos primeiro
          });
      }
      // 'default' mantém a ordem original (que já é baseada no campo 'order' do banco)

      return result;
  }, [topicPosts, searchTerm, filterStatus, filterRecorrencia, sortBy]);

  if (!topic) return <div className="text-center py-20">Não encontrado</div>;

  return (
    <div>
      <div className="mb-10 flex flex-col md:flex-row md:items-end justify-between border-b border-slate-800 pb-6 gap-6">
        <div>
          <Link to="/" className="text-xs text-slate-500 hover:text-white flex items-center gap-1 mb-2"><ArrowLeft size={12}/> Voltar ao Início</Link>
          <h2 className="text-3xl font-bold">{topic.label}</h2>
          <p className="text-slate-400 mt-1">{topic.description}</p>
        </div>

        {/* Barra de Ferramentas (Filtros e Busca) */}
        <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">

            {/* Busca */}
            <div className="relative group">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-emerald-500 transition-colors" size={14} />
                <input 
                    type="text" 
                    placeholder="Buscar..." 
                    value={searchTerm}
                    onChange={e => setSearchTerm(e.target.value)}
                    className="w-full sm:w-40 bg-slate-900 text-white text-xs py-2.5 pl-9 pr-4 rounded-xl border border-slate-800 outline-none focus:border-emerald-500 transition-all"
                />
            </div>

            {/* Filtro Status */}
            <div className="relative">
                <select 
                    value={filterStatus} 
                    onChange={e => setFilterStatus(e.target.value)}
                    className="w-full sm:w-32 appearance-none bg-slate-900 text-white text-xs font-bold uppercase pl-3 pr-8 py-2.5 rounded-xl border border-slate-800 focus:border-emerald-500 outline-none cursor-pointer hover:bg-slate-800 transition-all"
                >
                    <option value="all">Todos Status</option>
                    <option value="green">Normal</option>
                    <option value="yellow">Atenção</option>
                    <option value="red">Crítico</option>
                </select>
                <div className={`absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none w-2 h-2 rounded-full ${filterStatus === 'green' ? 'bg-emerald-500' : filterStatus === 'yellow' ? 'bg-amber-500' : filterStatus === 'red' ? 'bg-red-500' : 'bg-slate-600'}`}></div>
            </div>

            {/* Filtro Periodicidade */}
            <div className="relative">
                <select 
                    value={filterRecorrencia} 
                    onChange={e => setFilterRecorrencia(e.target.value)}
                    className="w-full sm:w-32 appearance-none bg-slate-900 text-white text-xs font-bold uppercase pl-3 pr-8 py-2.5 rounded-xl border border-slate-800 focus:border-emerald-500 outline-none cursor-pointer hover:bg-slate-800 transition-all"
                >
                    <option value="all">Período</option>
                    {uniqueRecorrencias.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
                <Filter className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={12}/>
            </div>

            {/* Ordenação */}
            <div className="relative">
                <select 
                    value={sortBy} 
                    onChange={e => setSortBy(e.target.value as any)}
                    className="w-full sm:w-32 appearance-none bg-slate-900 text-white text-xs font-bold uppercase pl-3 pr-8 py-2.5 rounded-xl border border-slate-800 focus:border-emerald-500 outline-none cursor-pointer hover:bg-slate-800 transition-all"
                >
                    <option value="default">Padrão</option>
                    <option value="alpha">A-Z</option>
                    <option value="status">Prioridade</option>
                </select>
                <ArrowUpDown className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" size={12}/>
            </div>

        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
        {processedPosts.length > 0 ? processedPosts.map(post => {
            const status = post.semaforoGeral || 'green';
            const rules = post.semaforoRules || { green: 'Normal', yellow: 'Atenção', red: 'Crítico' };
            const progressColor = post.progress >= 100 ? 'bg-emerald-500' : post.progress > 50 ? 'bg-blue-500' : 'bg-amber-500';

            return (
          // Removido overflow-hidden e adicionado rounded-t-3xl no header interno para permitir tooltip
          <div key={post.id} className="bg-slate-900/40 border border-slate-800/60 rounded-3xl hover:border-emerald-500/50 hover:z-20 transition-all flex flex-col h-full group relative">

            <div className="p-6 flex items-start justify-between bg-slate-900/80 border-b border-slate-800 relative z-10 rounded-t-3xl">
              <div className="flex items-start gap-5 pr-10 w-full">
                 <div className="mt-1 shrink-0">
                    <SemaforoWithTooltip status={status} rules={rules} sizeClass="w-12 h-12" />
                 </div>

                 <div className="flex-1">
                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{post.recorrencia}</span>
                    {/* Exibe o Nome do Indicador (Principal) ou fallback para o Título do Gráfico */}
                    <h3 className="font-bold text-lg text-slate-100 leading-tight mt-1">{post.indicatorName || post.chartConfig.title}</h3>
                 </div>
              </div>
              <button onClick={() => setSelectedPost(post)} className="p-2.5 bg-slate-800 text-slate-400 hover:text-white hover:bg-emerald-600 rounded-xl transition-all absolute top-6 right-6"><Maximize2 size={18}/></button>
            </div>

            <div className="p-6 flex-1 space-y-6">
              {/* Gráfico Reduzido, AUMENTADO DE h-52 PARA h-64 para evitar cortes */}
              <div className="h-64 bg-[#0B1120] rounded-2xl p-4 border border-slate-800/80 shadow-inner overflow-hidden relative group-hover:shadow-[inset_0_0_20px_rgba(16,185,129,0.05)] transition-all">
                <ChartRenderer config={post.chartConfig} />
              </div>

              {/* Barra de Progresso */}
              <div className="space-y-2">
                <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase tracking-tighter">
                  <span>Execução da Meta</span>
                  <span className={`${post.progress >= 100 ? 'text-emerald-400' : 'text-slate-200'}`}>{post.progress}%</span>
                </div>
                <div className="h-3 bg-slate-950 rounded-full overflow-hidden border border-slate-800/50 shadow-inner relative">
                  <div className={`h-full ${progressColor} transition-all duration-1000 relative`} style={{ width: `${post.progress}%` }}>
                     <div className="absolute inset-0 bg-[linear-gradient(45deg,rgba(255,255,255,0.15)_25%,transparent_25%,transparent_50%,rgba(255,255,255,0.15)_50%,rgba(255,255,255,0.15)_75%,transparent_75%,transparent)] bg-[length:1rem_1rem] opacity-50 animate-[pulse_2s_linear_infinite]"></div>
                  </div>
                </div>
              </div>

              <div className="flex items-center justify-between text-[10px] text-slate-500 font-bold border-t border-slate-800 pt-4">
                <span className="flex items-center gap-1.5"><User size={12}/> {post.responsavel}</span>
                <span className="flex items-center gap-1.5"><Clock size={12}/> {new Date(post.dataAtualizacao).toLocaleDateString()}</span>
              </div>
            </div>
          </div>
        )}) : (
            <div className="col-span-1 md:col-span-2 text-center py-20 text-slate-500 bg-slate-900/20 rounded-3xl border border-slate-800 border-dashed">
                <Search className="mx-auto mb-4 opacity-20" size={48} />
                <p className="text-sm font-bold uppercase">Nenhum indicador encontrado com os filtros atuais.</p>
            </div>
        )}
      </div>

      {selectedPost && (
        <ReportModal post={selectedPost} onClose={() => setSelectedPost(null)} />
      )}
    </div>
  );
};

export default App;

export enum TopicId {
  SAUDE = 'saude',
  EDUCACAO = 'educacao',
  DESENVOLVIMENTO_SOCIAL = 'social',
  FINANCAS = 'financas',
  ESPORTE_CULTURA_LAZER = 'esporte',
  AGRICULTURA = 'agricultura',
  INFRAESTRUTURA = 'infraestrutura',
  PLANEJAMENTO = 'planejamento',
}

export interface HistoricoItem {
  data: number; // Timestamp
  texto: string;
  tipo: 'conclusao' | 'atraso' | 'obs';
  autor: string;
}

export interface Etapa {
  id: string;
  descricao: string;
  prazo: string; // YYYY-MM-DD
  concluido: boolean;
  secretariaVinculada?: TopicId | ''; // Opcional: vínculo com outra secretaria
  observacao?: string;
}

export interface Meta {
  id: string;
  topicId: TopicId;
  titulo: string;
  descricao: string;

  // Controle de Prazos
  prazoGeral: string; // YYYY-MM-DD
  diasAlerta: number; // Quantos dias antes do prazo para ficar amarelo

  // Controle de Dados
  etapas: Etapa[];
  historico: HistoricoItem[];

  // Metadados
  responsavel: string;
  createdAt: number;
  dataAtualizacao: number;
  lastEditor?: string;
  order?: number;

  // Propriedades calculadas no Frontend (não salvas no banco necessariamente, mas usadas na UI)
  computedStatus?: 'green' | 'yellow' | 'red';
  computedProgress?: number;
}

export interface TopicDef {
  id: TopicId;
  label: string;
  iconName: string;
  color: string;
  description: string;
}

import React, { useState, useRef } from 'react';
import { X, Plus, Lock, Save, Trash2, Calendar, LayoutList, AlertTriangle, User, FileText, CheckSquare, Square, Link as LinkIcon } from 'lucide-react';
import { Meta, TopicId, Etapa, HistoricoItem } from '../types';
import { TOPICS } from '../constants';

interface AdminPanelProps {
  isOpen: boolean;
  onClose: () => void;
  posts: Meta[]; // Posts agora são Metas
  onAddPost: (meta: Omit<Meta, 'id' | 'createdAt' | 'order'>) => Promise<boolean | void>;
  onEditPost: (id: string, meta: Partial<Meta>) => Promise<boolean | void>;
  onDeletePost: (postId: string) => void;
  usingServer: boolean;
}

const USERS_MAP: Record<string, string> = {
  'azul': 'Lucas Araujo dos Santos',
  'amarelo': 'Gilda Natali Mendes dos Santos Lemos',
  'preto': 'Ana Paula Daltro Oliveira',
  'rosa': 'Maiara dos Santos Maia'
};

export const AdminPanel: React.FC<AdminPanelProps> = ({ 
  isOpen, onClose, posts, onAddPost, onEditPost, onDeletePost
}) => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [currentUser, setCurrentUser] = useState('');
  const [passwordInput, setPasswordInput] = useState('');
  const [loginError, setLoginError] = useState('');

  const [activeTab, setActiveTab] = useState<'form' | 'list'>('form');
  const [editingId, setEditingId] = useState<string | null>(null);

  // Form State
  const [topicId, setTopicId] = useState<TopicId>(TopicId.EDUCACAO);
  const [titulo, setTitulo] = useState('');
  const [descricao, setDescricao] = useState('');
  const [prazoGeral, setPrazoGeral] = useState('');
  const [diasAlerta, setDiasAlerta] = useState(7); // Padrão 7 dias para alerta
  const [responsavel, setResponsavel] = useState('');

  // Etapas State
  const [etapas, setEtapas] = useState<Etapa[]>([]);
  const [historico, setHistorico] = useState<HistoricoItem[]>([]);
  const [novaObs, setNovaObs] = useState('');
  const [tipoObs, setTipoObs] = useState<'obs' | 'atraso'>('obs');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const normalizedPass = passwordInput.trim().toLowerCase();
    if (USERS_MAP[normalizedPass]) {
      setIsAuthenticated(true);
      setCurrentUser(USERS_MAP[normalizedPass]);
    } else {
      setLoginError('Senha incorreta.');
    }
  };

  const resetForm = () => {
    setEditingId(null);
    setTitulo('');
    setDescricao('');
    setPrazoGeral('');
    setDiasAlerta(7);
    setResponsavel('');
    setEtapas([]);
    setHistorico([]);
    setNovaObs('');
  };

  const handleEditClick = (meta: Meta) => {
    setEditingId(meta.id);
    setTopicId(meta.topicId);
    setTitulo(meta.titulo);
    setDescricao(meta.descricao);
    setPrazoGeral(meta.prazoGeral);
    setDiasAlerta(meta.diasAlerta);
    setResponsavel(meta.responsavel);
    setEtapas(meta.etapas || []);
    setHistorico(meta.historico || []);
    setActiveTab('form');
  };

  const addEtapa = () => {
    const novaEtapa: Etapa = {
        id: Date.now().toString(),
        descricao: '',
        prazo: prazoGeral, // Herda o prazo geral por padrão
        concluido: false,
        secretariaVinculada: ''
    };
    setEtapas([...etapas, novaEtapa]);
  };

  const updateEtapa = (index: number, field: keyof Etapa, value: any) => {
    const novas = [...etapas];
    (novas[index] as any)[field] = value;

    // Se marcou como concluído, podemos adicionar histórico automático (opcional)
    if (field === 'concluido' && value === true && !novas[index].dataConclusao) {
        novas[index].dataConclusao = new Date().toISOString();
    }
    setEtapas(novas);
  };

  const removeEtapa = (index: number) => {
    setEtapas(etapas.filter((_, i) => i !== index));
  };

  const handleSubmit = async () => {
    if (!titulo || !prazoGeral) {
        alert("Título e Prazo Geral são obrigatórios.");
        return;
    }

    // Processar nova observação se houver
    let finalHistorico = [...historico];
    if (novaObs.trim()) {
        finalHistorico.push({
            data: Date.now(),
            texto: novaObs,
            tipo: tipoObs,
            autor: currentUser
        });
    }

    const metaData = {
        topicId,
        titulo,
        descricao,
        prazoGeral,
        diasAlerta,
        responsavel,
        etapas,
        historico: finalHistorico,
        dataAtualizacao: Date.now(),
        lastEditor: currentUser
    };

    let success;
    if (editingId) {
        success = await onEditPost(editingId, metaData);
    } else {
        success = await onAddPost(metaData);
    }

    if (success !== false) {
        resetForm();
        setActiveTab('list');
    }
  };

  if (!isAuthenticated) {
    return (
     <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 backdrop-blur-2xl p-4">
       <div className="bg-slate-900 border border-slate-700 rounded-3xl p-8 md:p-12 w-full max-w-sm text-center space-y-8 shadow-2xl">
         <div className="w-20 h-20 bg-emerald-500/10 rounded-full flex items-center justify-center mx-auto border border-emerald-500/20"><Lock className="text-emerald-400" size={32}/></div>
         <h2 className="text-2xl font-black text-white uppercase tracking-tighter">Gestão Técnica</h2>
         <form onSubmit={handleLogin} className="space-y-4">
           <input type="password" value={passwordInput} onChange={e => { setPasswordInput(e.target.value); setLoginError(''); }} placeholder="Senha" className={`w-full p-4 bg-slate-950 border ${loginError ? 'border-red-500' : 'border-slate-800'} rounded-2xl text-white text-center font-black outline-none focus:ring-2 focus:ring-emerald-500`} autoFocus />
           {loginError && <p className="text-red-400 text-xs font-bold mt-2">{loginError}</p>}
           <button type="submit" className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black uppercase hover:bg-emerald-500 transition-all">Acessar</button>
         </form>
       </div>
     </div>
   );
 }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/90 backdrop-blur-md p-4">
      <div className="bg-[#0f172a] border border-slate-800 rounded-[2rem] w-full max-w-5xl h-[95vh] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">

        {/* Header */}
        <div className="p-6 border-b border-slate-800 bg-slate-900/50 flex justify-between items-center shrink-0">
            <div className="flex items-center gap-4">
                <div className="p-3 bg-emerald-500/10 rounded-xl border border-emerald-500/20">
                    <CheckSquare className="text-emerald-400" size={24} />
                </div>
                <div>
                    <h2 className="text-xl font-black text-white uppercase tracking-tight">Gestão de Metas</h2>
                    <p className="text-xs text-slate-500 font-bold">Usuário: {currentUser}</p>
                </div>
            </div>
            <div className="flex gap-2">
                <button onClick={() => { resetForm(); setActiveTab('form'); }} className={`px-4 py-2 rounded-xl text-xs font-black uppercase ${activeTab === 'form' ? 'bg-emerald-600 text-white' : 'bg-slate-800 text-slate-400 hover:text-white'}`}>Nova Meta</button>
                <button onClick={() => setActiveTab('list')} className={`px-4 py-2 rounded-xl text-xs font-black uppercase ${activeTab === 'list' ? 'bg-emerald-600 text-white' : 'bg-slate-800 text-slate-400 hover:text-white'}`}>Lista</button>
                <button onClick={onClose} className="p-2 hover:bg-red-500/20 hover:text-red-400 rounded-xl text-slate-500 transition-all ml-4"><X size={20}/></button>
            </div>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 md:p-10 custom-scrollbar">
            {activeTab === 'list' ? (
                <div className="space-y-4">
                    {posts.map(meta => (
                        <div key={meta.id} className="bg-slate-900/50 border border-slate-800 p-6 rounded-2xl flex justify-between items-center group hover:border-slate-700 transition-all">
                            <div>
                                <div className="flex items-center gap-2 mb-1">
                                    <span className={`text-[10px] font-black px-2 py-0.5 rounded uppercase border ${TOPICS.find(t => t.id === meta.topicId)?.color.replace('bg-', 'text-emerald-').replace('500','400').replace('600','400') || 'text-slate-400'} border-slate-700`}>{TOPICS.find(t => t.id === meta.topicId)?.label}</span>
                                    <span className="text-[10px] text-slate-500 font-bold uppercase">{new Date(meta.prazoGeral).toLocaleDateString()}</span>
                                </div>
                                <h3 className="text-lg font-bold text-white">{meta.titulo}</h3>
                                <p className="text-xs text-slate-400">{meta.etapas.filter(e => e.concluido).length}/{meta.etapas.length} etapas concluídas</p>
                            </div>
                            <div className="flex gap-2">
                                <button onClick={() => handleEditClick(meta)} className="p-3 bg-blue-500/10 text-blue-400 hover:bg-blue-500 hover:text-white rounded-xl transition-all"><LayoutList size={18}/></button>
                                <button onClick={() => onDeletePost(meta.id)} className="p-3 bg-red-500/10 text-red-400 hover:bg-red-500 hover:text-white rounded-xl transition-all"><Trash2 size={18}/></button>
                            </div>
                        </div>
                    ))}
                    {posts.length === 0 && <p className="text-center text-slate-500 py-10">Nenhuma meta cadastrada.</p>}
                </div>
            ) : (
                <div className="max-w-3xl mx-auto space-y-8">
                    {/* Bloco 1: Definição Geral */}
                    <section className="space-y-6 bg-slate-900/30 p-6 rounded-3xl border border-slate-800/50">
                        <h3 className="text-sm font-black text-white uppercase tracking-widest flex items-center gap-2 border-b border-slate-800 pb-2">
                            <FileText size={16} className="text-emerald-500"/> Definição da Meta
                        </h3>

                        <div className="grid md:grid-cols-2 gap-6">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-500 uppercase">Secretaria Responsável</label>
